&lt;p data-end=&quot;&quot; data-start=&quot;&quot;&gt;The correct answer is &lt;u&gt;&lt;strong&gt;1919&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li a=&quot;&quot; by=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; in=&quot;&quot; journal=&quot;&quot; li=&quot;&quot; mahatma=&quot;&quot; started=&quot;&quot; was=&quot;&quot; weekly=&quot;&quot; young=&quot;&quot;&gt;The paper served as a platform for Gandhi to express his views and disseminate ideas about &lt;strong&gt;non-violence, truth, and Satyagraha&lt;/strong&gt;.&lt;/li&gt;
	&lt;li .=&quot;&quot; about=&quot;&quot; aimed=&quot;&quot; and=&quot;&quot; at=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; educating=&quot;&quot; font-weight:=&quot;&quot; freedom=&quot;&quot; in=&quot;&quot; inspiring=&quot;&quot; is=&quot;&quot; li=&quot;&quot; masses=&quot;&quot; participate=&quot;&quot; philosophy=&quot;&quot; political=&quot;&quot; primarily=&quot;&quot; s=&quot;&quot; span=&quot;&quot; statement=&quot;&quot; style=&quot;&quot; the=&quot;&quot; them=&quot;&quot; to=&quot;&quot; was=&quot;&quot; young=&quot;&quot;&gt;Gandhi used this journal to critique the policies of the British government and promote his vision of &lt;strong&gt;Swaraj (self-rule)&lt;/strong&gt; for India.&lt;/li&gt;
	&lt;li .=&quot;&quot; 1919=&quot;&quot; also=&quot;&quot; and=&quot;&quot; color:=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; em=&quot;&quot; eradication=&quot;&quot; font-weight:=&quot;&quot; highlighted=&quot;&quot; is=&quot;&quot; issues=&quot;&quot; journal=&quot;&quot; key=&quot;&quot; li=&quot;&quot; like=&quot;&quot; of=&quot;&quot; rural=&quot;&quot; social=&quot;&quot; span=&quot;&quot; style=&quot;&quot; the=&quot;&quot; year=&quot;&quot;&gt;The paper was widely read and had a profound impact on both the educated and uneducated sections of Indian society, making it a crucial part of Gandhi&amp;rsquo;s communication strategy.&lt;/li&gt;
	&lt;li about=&quot;&quot; additional=&quot;&quot; align-items:=&quot;&quot; an=&quot;&quot; and=&quot;&quot; answer=&quot;&quot; cdn.testbook.com=&quot;&quot; civil=&quot;&quot; color:=&quot;&quot; correct=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; disobedience=&quot;&quot; display:=&quot;&quot; during=&quot;&quot; font-size:=&quot;&quot; gap:=&quot;&quot; height=&quot;&quot; img=&quot;&quot; in=&quot;&quot; instrumental=&quot;&quot; is=&quot;&quot; it=&quot;&quot; li=&quot;&quot; like=&quot;&quot; lms_creative_elements=&quot;&quot; major=&quot;&quot; mobilizing=&quot;&quot; movements=&quot;&quot; non-cooperation=&quot;&quot; people=&quot;&quot; played=&quot;&quot; resources=&quot;&quot; role=&quot;&quot; span=&quot;&quot; src=&quot;&quot; style=&quot;&quot; the=&quot;&quot; vertical-align:=&quot;&quot; width=&quot;&quot; young=&quot;&quot;&gt;&lt;strong&gt;Young India&lt;/strong&gt; was one of the most influential publications in India&amp;rsquo;s struggle for independence. It served as a medium for Gandhi to communicate his ideas to a broader audience.&lt;/li&gt;
	&lt;li also=&quot;&quot; and=&quot;&quot; attention=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; educated=&quot;&quot; freedom=&quot;&quot; gained=&quot;&quot; helped=&quot;&quot; in=&quot;&quot; indians=&quot;&quot; journal=&quot;&quot; li=&quot;&quot; reach=&quot;&quot; role=&quot;&quot; the=&quot;&quot; was=&quot;&quot; which=&quot;&quot; written=&quot;&quot;&gt;Gandhi used &lt;strong&gt;Young India&lt;/strong&gt; to criticize colonial policies and advocate for active resistance through &lt;strong&gt;non-violent means&lt;/strong&gt;.&lt;/li&gt;
	&lt;li a=&quot;&quot; about=&quot;&quot; against=&quot;&quot; and=&quot;&quot; awareness=&quot;&quot; became=&quot;&quot; british=&quot;&quot; campaigns=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; journal=&quot;&quot; khilafat=&quot;&quot; li=&quot;&quot; like=&quot;&quot; movements=&quot;&quot; other=&quot;&quot; spread=&quot;&quot; the=&quot;&quot; to=&quot;&quot; tool=&quot;&quot;&gt;&lt;strong&gt;Example:&lt;/strong&gt; Gandhi&amp;rsquo;s famous articles in &lt;strong&gt;Young India&lt;/strong&gt; included his philosophies on non-violence and his vision for a free India.&lt;/li&gt;
&lt;/ul&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Other Publications by Gandhi:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li a=&quot;&quot; addressing=&quot;&quot; also=&quot;&quot; and=&quot;&quot; apart=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; from=&quot;&quot; gandhi=&quot;&quot; issues=&quot;&quot; journal=&quot;&quot; li=&quot;&quot; related=&quot;&quot; social=&quot;&quot; started=&quot;&quot; to=&quot;&quot; untouchability=&quot;&quot; weekly=&quot;&quot; young=&quot;&quot;&gt;Gandhi&amp;rsquo;s writings in these journals were instrumental in shaping public opinion and mobilizing support for various movements.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span align-items:=&quot;&quot; display:=&quot;&quot; gap:=&quot;&quot; style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Other Significant Dates:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li and=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; gandhi=&quot;&quot; hind=&quot;&quot; his=&quot;&quot; li=&quot;&quot; non-violent=&quot;&quot; of=&quot;&quot; outlined=&quot;&quot; published=&quot;&quot; self-rule=&quot;&quot; vision=&quot;&quot; which=&quot;&quot;&gt;&lt;strong&gt;1932:&lt;/strong&gt; Gandhi started the &lt;strong&gt;Harijan&lt;/strong&gt; publication to address social issues, particularly untouchability.&lt;/li&gt;
		&lt;li actively=&quot;&quot; africa=&quot;&quot; and=&quot;&quot; began=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; freedom=&quot;&quot; from=&quot;&quot; gandhi=&quot;&quot; impact=&quot;&quot; in=&quot;&quot; india=&quot;&quot; indian=&quot;&quot; li=&quot;&quot; of=&quot;&quot; participating=&quot;&quot; returned=&quot;&quot; south=&quot;&quot; the=&quot;&quot; to=&quot;&quot; young=&quot;&quot;&gt;The journal had a lasting impact on the Indian independence movement, influencing both national and international audiences.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p data-end=&quot;&quot; data-start=&quot;&quot;&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;1919&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;मुख्य बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li a=&quot;&quot; by=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; in=&quot;&quot; journal=&quot;&quot; li=&quot;&quot; mahatma=&quot;&quot; started=&quot;&quot; was=&quot;&quot; weekly=&quot;&quot; young=&quot;&quot;&gt;इस पत्र ने गांधीजी को अपने विचार व्यक्त करने और &lt;strong&gt;अहिंसा, सत्य और सत्याग्रह&lt;/strong&gt; के बारे में विचारों का प्रसार करने के लिए एक मंच के रूप में कार्य किया।&lt;/li&gt;
	&lt;li .=&quot;&quot; about=&quot;&quot; aimed=&quot;&quot; and=&quot;&quot; at=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; educating=&quot;&quot; font-weight:=&quot;&quot; freedom=&quot;&quot; in=&quot;&quot; inspiring=&quot;&quot; is=&quot;&quot; li=&quot;&quot; masses=&quot;&quot; participate=&quot;&quot; philosophy=&quot;&quot; political=&quot;&quot; primarily=&quot;&quot; s=&quot;&quot; span=&quot;&quot; statement=&quot;&quot; style=&quot;&quot; the=&quot;&quot; them=&quot;&quot; to=&quot;&quot; was=&quot;&quot; young=&quot;&quot;&gt;गांधीजी ने इस पत्रिका का उपयोग ब्रिटिश सरकार की नीतियों की आलोचना करने और भारत के लिए &lt;strong&gt;स्वराज (स्व-शासन)&lt;/strong&gt; की अपनी दृष्टि को बढ़ावा देने के लिए किया।&lt;/li&gt;
	&lt;li .=&quot;&quot; 1919=&quot;&quot; also=&quot;&quot; and=&quot;&quot; color:=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; em=&quot;&quot; eradication=&quot;&quot; font-weight:=&quot;&quot; highlighted=&quot;&quot; is=&quot;&quot; issues=&quot;&quot; journal=&quot;&quot; key=&quot;&quot; li=&quot;&quot; like=&quot;&quot; of=&quot;&quot; rural=&quot;&quot; social=&quot;&quot; span=&quot;&quot; style=&quot;&quot; the=&quot;&quot; year=&quot;&quot;&gt;यह पत्र व्यापक रूप से पढ़ा गया और भारतीय समाज के शिक्षित और अशिक्षित दोनों वर्गों पर इसका गहरा प्रभाव पड़ा, जिससे यह गांधीजी की संचार रणनीति का एक महत्वपूर्ण हिस्सा बन गया।&lt;/li&gt;
	&lt;li about=&quot;&quot; additional=&quot;&quot; align-items:=&quot;&quot; an=&quot;&quot; and=&quot;&quot; answer=&quot;&quot; cdn.testbook.com=&quot;&quot; civil=&quot;&quot; color:=&quot;&quot; correct=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; disobedience=&quot;&quot; display:=&quot;&quot; during=&quot;&quot; font-size:=&quot;&quot; gap:=&quot;&quot; height=&quot;&quot; img=&quot;&quot; in=&quot;&quot; instrumental=&quot;&quot; is=&quot;&quot; it=&quot;&quot; li=&quot;&quot; like=&quot;&quot; lms_creative_elements=&quot;&quot; major=&quot;&quot; mobilizing=&quot;&quot; movements=&quot;&quot; non-cooperation=&quot;&quot; people=&quot;&quot; played=&quot;&quot; resources=&quot;&quot; role=&quot;&quot; span=&quot;&quot; src=&quot;&quot; style=&quot;&quot; the=&quot;&quot; vertical-align:=&quot;&quot; width=&quot;&quot; young=&quot;&quot;&gt;&lt;strong&gt;यंग इंडिया&lt;/strong&gt; भारत के स्वतंत्रता संग्राम में सबसे प्रभावशाली प्रकाशनों में से एक था। इसने गांधीजी के विचारों को व्यापक दर्शकों तक पहुंचाने के लिए एक माध्यम के रूप में कार्य किया।&lt;/li&gt;
	&lt;li also=&quot;&quot; and=&quot;&quot; attention=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; educated=&quot;&quot; freedom=&quot;&quot; gained=&quot;&quot; helped=&quot;&quot; in=&quot;&quot; indians=&quot;&quot; journal=&quot;&quot; li=&quot;&quot; reach=&quot;&quot; role=&quot;&quot; the=&quot;&quot; was=&quot;&quot; which=&quot;&quot; written=&quot;&quot;&gt;गांधीजी ने &lt;strong&gt;यंग इंडिया&lt;/strong&gt; का उपयोग औपनिवेशिक नीतियों की आलोचना करने और &lt;strong&gt;अहिंसक साधनों&lt;/strong&gt; के माध्यम से सक्रिय प्रतिरोध की वकालत करने के लिए किया।&lt;/li&gt;
	&lt;li a=&quot;&quot; about=&quot;&quot; against=&quot;&quot; and=&quot;&quot; awareness=&quot;&quot; became=&quot;&quot; british=&quot;&quot; campaigns=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; journal=&quot;&quot; khilafat=&quot;&quot; li=&quot;&quot; like=&quot;&quot; movements=&quot;&quot; other=&quot;&quot; spread=&quot;&quot; the=&quot;&quot; to=&quot;&quot; tool=&quot;&quot;&gt;&lt;strong&gt;उदाहरण:&lt;/strong&gt; &lt;strong&gt;यंग इंडिया&lt;/strong&gt; में गांधीजी के प्रसिद्ध लेखों में अहिंसा पर उनके दर्शन और एक स्वतंत्र भारत के लिए उनकी दृष्टि शामिल थी।&lt;/li&gt;
&lt;/ul&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;गांधीजी द्वारा अन्य प्रकाशन:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li a=&quot;&quot; addressing=&quot;&quot; also=&quot;&quot; and=&quot;&quot; apart=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; from=&quot;&quot; gandhi=&quot;&quot; issues=&quot;&quot; journal=&quot;&quot; li=&quot;&quot; related=&quot;&quot; social=&quot;&quot; started=&quot;&quot; to=&quot;&quot; untouchability=&quot;&quot; weekly=&quot;&quot; young=&quot;&quot;&gt;इन पत्रिकाओं में गांधीजी के लेखन सार्वजनिक राय को आकार देने और विभिन्न आंदोलनों के लिए समर्थन जुटाने में सहायक थे।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span align-items:=&quot;&quot; display:=&quot;&quot; gap:=&quot;&quot; style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;महत्वपूर्ण बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;अन्य महत्वपूर्ण तिथियां:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li and=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; gandhi=&quot;&quot; hind=&quot;&quot; his=&quot;&quot; li=&quot;&quot; non-violent=&quot;&quot; of=&quot;&quot; outlined=&quot;&quot; published=&quot;&quot; self-rule=&quot;&quot; vision=&quot;&quot; which=&quot;&quot;&gt;&lt;strong&gt;1932:&lt;/strong&gt; गांधीजी ने सामाजिक मुद्दों, विशेष रूप से अस्पृश्यता को संबोधित करने के लिए &lt;strong&gt;हरिजन&lt;/strong&gt; प्रकाशन शुरू किया।&lt;/li&gt;
		&lt;li actively=&quot;&quot; africa=&quot;&quot; and=&quot;&quot; began=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; freedom=&quot;&quot; from=&quot;&quot; gandhi=&quot;&quot; impact=&quot;&quot; in=&quot;&quot; india=&quot;&quot; indian=&quot;&quot; li=&quot;&quot; of=&quot;&quot; participating=&quot;&quot; returned=&quot;&quot; south=&quot;&quot; the=&quot;&quot; to=&quot;&quot; young=&quot;&quot;&gt;इस पत्रिका का भारतीय स्वतंत्रता आंदोलन पर स्थायी प्रभाव पड़ा, जिसने राष्ट्रीय और अंतर्राष्ट्रीय दोनों दर्शकों को प्रभावित किया।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p data-end=&quot;57&quot; data-start=&quot;0&quot;&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Company&amp;rsquo;s constitution in Britain and territorial rule in India&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p data-end=&quot;57&quot; data-start=&quot;0&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;284&quot; data-start=&quot;78&quot;&gt;The &lt;strong&gt;Regulating Act of 1773&lt;/strong&gt; was the first significant legislative attempt by the British government to regulate the affairs of the &lt;strong&gt;East India Company&lt;/strong&gt; in India.&lt;/li&gt;
	&lt;li data-end=&quot;605&quot; data-start=&quot;482&quot;&gt;It introduced reforms in the &lt;strong&gt;Company&amp;rsquo;s administration&lt;/strong&gt; by changing its constitution in Britain and addressing the governance of territories in India.&lt;/li&gt;
	&lt;li data-end=&quot;692&quot; data-start=&quot;610&quot;&gt;The Act sought to centralize administration and ensure better control over the &lt;strong&gt;Company&amp;rsquo;s operations&lt;/strong&gt;, both in India and in Britain. &lt;em&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Hence, statement 2 is correct.&lt;/span&gt;&lt;/em&gt;&lt;/li&gt;
	&lt;li data-end=&quot;1041&quot; data-start=&quot;850&quot;&gt;It established a &lt;strong&gt;Governor-General of Bengal&lt;/strong&gt; and a council to supervise and control the Company&amp;rsquo;s territorial acquisitions and administration in India.&lt;/li&gt;
	&lt;li data-end=&quot;1162&quot; data-start=&quot;1046&quot;&gt;The Act also required the Company to submit its accounts and finances to the British government to ensure greater accountability.&amp;nbsp;&lt;em style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Hence, statement 2&amp;nbsp;is correct.&lt;/span&gt;&lt;/em&gt;&lt;/li&gt;
	&lt;li data-end=&quot;1560&quot; data-start=&quot;1323&quot;&gt;It did not primarily deal with the &lt;strong&gt;Company&amp;rsquo;s military or trade control&lt;/strong&gt;, nor did it focus on foreign relations or shipping trade. These aspects were secondary or indirect outcomes of the administrative restructuring.&lt;/li&gt;
	&lt;li data-end=&quot;1654&quot; data-start=&quot;1565&quot;&gt;The Act laid the foundation for subsequent laws and policies aimed at regulating the affairs of the East India Company. &lt;em style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Hence, the correct answer is Company&amp;rsquo;s constitution in Britain and territorial rule in India.&lt;/span&gt;&lt;/em&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Provisions of the Regulating Act of 1773:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;2410&quot; data-start=&quot;2195&quot;&gt;The Act provided for the appointment of a &lt;strong&gt;Governor-General of Bengal&lt;/strong&gt;, assisted by a council of four members. The first Governor-General was &lt;strong&gt;Warren Hastings&lt;/strong&gt;.&lt;/li&gt;
		&lt;li data-end=&quot;2684&quot; data-start=&quot;2415&quot;&gt;It mandated that the &lt;strong&gt;Company&amp;rsquo;s territories&lt;/strong&gt; in Bengal, Bombay, and Madras be overseen by the Governor-General of Bengal, establishing a central authority.&lt;/li&gt;
		&lt;li data-end=&quot;2860&quot; data-start=&quot;2735&quot;&gt;The Act made the East India Company accountable to the &lt;strong&gt;British Parliament&lt;/strong&gt;, requiring them to submit regular reports and accounts.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Impact of the Regulating Act:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;3071&quot; data-start=&quot;2865&quot;&gt;It marked the beginning of &lt;strong&gt;British parliamentary control&lt;/strong&gt; over the East India Company&amp;rsquo;s operations in India.&lt;/li&gt;
		&lt;li data-end=&quot;3250&quot; data-start=&quot;3076&quot;&gt;The Act attempted to address the widespread corruption and inefficiency in the administration of the Company&amp;rsquo;s territories.&lt;/li&gt;
		&lt;li data-end=&quot;3402&quot; data-start=&quot;3301&quot;&gt;It laid the foundation for the establishment of a systematic and centralized administrative framework in India, influencing future reforms like the &lt;strong&gt;Pitt&amp;rsquo;s India Act of 1784&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Limitations of the Act:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;3580&quot; data-start=&quot;3407&quot;&gt;The Act did not address the Company&amp;rsquo;s trade operations or military control directly.&lt;/li&gt;
		&lt;li data-end=&quot;3729&quot; data-start=&quot;3585&quot;&gt;It faced criticism for its inability to fully curb corruption and inefficiencies within the Company&amp;rsquo;s administration.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Key Aspects of the Regulating Act:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;4636&quot; data-start=&quot;4411&quot;&gt;The Act established a &lt;strong&gt;Supreme Court&lt;/strong&gt; in Calcutta in 1774 to administer justice in the Company&amp;rsquo;s territories.&lt;/li&gt;
		&lt;li data-end=&quot;4761&quot; data-start=&quot;4641&quot;&gt;It marked the beginning of a dual system of government, where the Company retained commercial privileges, but administrative control shifted to the British Crown.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Historical Significance:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;5043&quot; data-start=&quot;4817&quot;&gt;The Regulating Act was a precursor to future legislative measures such as the &lt;strong&gt;Pitt&amp;rsquo;s India Act of 1784&lt;/strong&gt;, which further strengthened British control over the Company.&lt;/li&gt;
		&lt;li data-end=&quot;5259&quot; data-start=&quot;5048&quot;&gt;It represented a shift in the nature of British involvement in India, transitioning from commercial exploitation to direct territorial governance.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p data-end=&quot;57&quot; data-start=&quot;0&quot;&gt;सही उत्तर है &lt;u&gt;&lt;strong&gt;ब्रिटेन में कंपनी का संविधान और भारत में क्षेत्रीय शासन&lt;/strong&gt;&lt;/u&gt;।&lt;/p&gt;

&lt;p data-end=&quot;57&quot; data-start=&quot;0&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;मुख्य बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;284&quot; data-start=&quot;78&quot;&gt;&lt;strong&gt;1773 का विनियमन अधिनियम&lt;/strong&gt; ब्रिटिश सरकार द्वारा भारत में &lt;strong&gt;ईस्ट इंडिया कंपनी&lt;/strong&gt; के मामलों को विनियमित करने का पहला महत्वपूर्ण विधायी प्रयास था।&lt;/li&gt;
	&lt;li data-end=&quot;605&quot; data-start=&quot;482&quot;&gt;इसने ब्रिटेन में इसके संविधान को बदलकर और भारत में क्षेत्रों के शासन को संबोधित करके &lt;strong&gt;कंपनी के प्रशासन&lt;/strong&gt; में सुधार पेश किए।&lt;/li&gt;
	&lt;li data-end=&quot;692&quot; data-start=&quot;610&quot;&gt;अधिनियम ने प्रशासन को केंद्रीकृत करने और भारत और ब्रिटेन दोनों में &lt;strong&gt;कंपनी के संचालन&lt;/strong&gt; पर बेहतर नियंत्रण सुनिश्चित करने की मांग की। &lt;em&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;इसलिए, कथन 2 सही है।&lt;/span&gt;&lt;/em&gt;&lt;/li&gt;
	&lt;li data-end=&quot;1041&quot; data-start=&quot;850&quot;&gt;इसने भारत में कंपनी के क्षेत्रीय अधिग्रहण और प्रशासन की निगरानी और नियंत्रण के लिए &lt;strong&gt;बंगाल के गवर्नर-जनरल&lt;/strong&gt; और एक परिषद की स्थापना की।&lt;/li&gt;
	&lt;li data-end=&quot;1162&quot; data-start=&quot;1046&quot;&gt;अधिनियम में कंपनी को अधिक जवाबदेही सुनिश्चित करने के लिए अपने खातों और वित्त को ब्रिटिश सरकार को सौंपने की भी आवश्यकता थी। &lt;em style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;इसलिए, कथन 2 सही है।&lt;/span&gt;&lt;/em&gt;&lt;/li&gt;
	&lt;li data-end=&quot;1560&quot; data-start=&quot;1323&quot;&gt;इसने मुख्य रूप से &lt;strong&gt;कंपनी के सैन्य या व्यापार नियंत्रण&lt;/strong&gt; से निपटा नहीं, न ही इसने विदेशी संबंधों या शिपिंग व्यापार पर ध्यान केंद्रित किया। ये पहलू प्रशासनिक पुनर्गठन के द्वितीयक या अप्रत्यक्ष परिणाम थे।&lt;/li&gt;
	&lt;li data-end=&quot;1654&quot; data-start=&quot;1565&quot;&gt;अधिनियम ने ईस्ट इंडिया कंपनी के मामलों को विनियमित करने के उद्देश्य से बाद के कानूनों और नीतियों की नींव रखी। &lt;em style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;इसलिए, सही उत्तर ब्रिटेन में कंपनी का संविधान और भारत में क्षेत्रीय शासन है।&lt;/span&gt;&lt;/em&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;अतिरिक्त जानकारी&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;1773 के विनियमन अधिनियम के प्रावधान:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;2410&quot; data-start=&quot;2195&quot;&gt;अधिनियम में चार सदस्यों की परिषद द्वारा सहायता प्राप्त &lt;strong&gt;बंगाल के गवर्नर-जनरल&lt;/strong&gt; की नियुक्ति का प्रावधान था। पहले गवर्नर-जनरल &lt;strong&gt;वारेन हेस्टिंग्स&lt;/strong&gt; थे।&lt;/li&gt;
		&lt;li data-end=&quot;2684&quot; data-start=&quot;2415&quot;&gt;इसने अनिवार्य किया कि बंगाल, बॉम्बे और मद्रास में &lt;strong&gt;कंपनी के क्षेत्रों&lt;/strong&gt; की देखरेख बंगाल के गवर्नर-जनरल द्वारा की जाए, जिससे एक केंद्रीय प्राधिकरण स्थापित हो।&lt;/li&gt;
		&lt;li data-end=&quot;2860&quot; data-start=&quot;2735&quot;&gt;अधिनियम ने ईस्ट इंडिया कंपनी को &lt;strong&gt;ब्रिटिश संसद&lt;/strong&gt; के प्रति जवाबदेह बनाया, जिससे उन्हें नियमित रिपोर्ट और खाते जमा करने की आवश्यकता हुई।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;विनियमन अधिनियम का प्रभाव:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;3071&quot; data-start=&quot;2865&quot;&gt;इसने भारत में ईस्ट इंडिया कंपनी के संचालन पर &lt;strong&gt;ब्रिटिश संसदीय नियंत्रण&lt;/strong&gt; की शुरुआत को चिह्नित किया।&lt;/li&gt;
		&lt;li data-end=&quot;3250&quot; data-start=&quot;3076&quot;&gt;अधिनियम ने कंपनी के क्षेत्रों के प्रशासन में व्यापक भ्रष्टाचार और अक्षमता को दूर करने का प्रयास किया।&lt;/li&gt;
		&lt;li data-end=&quot;3402&quot; data-start=&quot;3301&quot;&gt;इसने भारत में एक व्यवस्थित और केंद्रीकृत प्रशासनिक ढांचे की स्थापना की नींव रखी, जिसने &lt;strong&gt;1784 के पिट्स इंडिया एक्ट&lt;/strong&gt; जैसे भविष्य के सुधारों को प्रभावित किया।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;अधिनियम की सीमाएँ:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;3580&quot; data-start=&quot;3407&quot;&gt;अधिनियम ने कंपनी के व्यापार संचालन या सैन्य नियंत्रण को सीधे संबोधित नहीं किया।&lt;/li&gt;
		&lt;li data-end=&quot;3729&quot; data-start=&quot;3585&quot;&gt;इसने कंपनी के प्रशासन के भीतर भ्रष्टाचार और अक्षमताओं को पूरी तरह से रोकने में अपनी अक्षमता के लिए आलोचना का सामना किया।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;महत्वपूर्ण बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;विनियमन अधिनियम के मुख्य पहलू:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;4636&quot; data-start=&quot;4411&quot;&gt;अधिनियम ने कंपनी के क्षेत्रों में न्याय प्रशासन के लिए 1774 में कलकत्ता में एक &lt;strong&gt;सुप्रीम कोर्ट&lt;/strong&gt; की स्थापना की।&lt;/li&gt;
		&lt;li data-end=&quot;4761&quot; data-start=&quot;4641&quot;&gt;इसने सरकार की दोहरी प्रणाली की शुरुआत को चिह्नित किया, जहां कंपनी ने वाणिज्यिक विशेषाधिकार बरकरार रखे, लेकिन प्रशासनिक नियंत्रण ब्रिटिश क्राउन को स्थानांतरित हो गया।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;ऐतिहासिक महत्व:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;5043&quot; data-start=&quot;4817&quot;&gt;विनियमन अधिनियम भविष्य के विधायी उपायों जैसे कि &lt;strong&gt;1784 का पिट्स इंडिया एक्ट&lt;/strong&gt; का अग्रदूत था, जिसने कंपनी पर ब्रिटिश नियंत्रण को और मजबूत किया।&lt;/li&gt;
		&lt;li data-end=&quot;5259&quot; data-start=&quot;5048&quot;&gt;इसने भारत में ब्रिटिश भागीदारी की प्रकृति में बदलाव का प्रतिनिधित्व किया, वाणिज्यिक शोषण से प्रत्यक्ष क्षेत्रीय शासन में परिवर्तन हुआ।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p data-end=&quot;57&quot; data-start=&quot;0&quot;&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Second Plan&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p data-end=&quot;57&quot; data-start=&quot;0&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;284&quot; data-start=&quot;78&quot;&gt;The &lt;strong&gt;Second Five-Year Plan (1956-1961)&lt;/strong&gt; placed a major emphasis on the development of &lt;strong&gt;heavy industries&lt;/strong&gt; in India. It was based on the &lt;strong&gt;Mahalnobis Model&lt;/strong&gt;, which prioritized industrialization as a strategy to achieve economic growth.&lt;/li&gt;
	&lt;li data-end=&quot;605&quot; data-start=&quot;482&quot;&gt;The main focus was on developing industries such as &lt;strong&gt;steel, coal, cement, and heavy machinery&lt;/strong&gt;, which were considered essential for infrastructure development and economic self-reliance.&lt;/li&gt;
	&lt;li data-end=&quot;692&quot; data-start=&quot;610&quot;&gt;This plan aimed to promote the establishment of &lt;strong&gt;public sector enterprises&lt;/strong&gt; to drive industrial growth, as private capital was limited during that period.&lt;/li&gt;
	&lt;li data-end=&quot;1041&quot; data-start=&quot;850&quot;&gt;The emphasis on heavy industries was seen as a means to create a strong foundation for &lt;strong&gt;long-term economic development&lt;/strong&gt; and reduce dependence on foreign imports.&lt;/li&gt;
	&lt;li data-end=&quot;1162&quot; data-start=&quot;1046&quot;&gt;The plan also aimed to reduce unemployment and improve socio-economic conditions by boosting industrial production and creating more job opportunities in the industrial sector.&lt;/li&gt;
	&lt;li data-end=&quot;1654&quot; data-start=&quot;1565&quot;&gt;&lt;em style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Hence, the Second Plan placed a major emphasis on heavy industries.&lt;/span&gt;&lt;/em&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;First Five-Year Plan (1951-1956):&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;2410&quot; data-start=&quot;2195&quot;&gt;The First Plan focused on &lt;strong&gt;agriculture, irrigation, and rural development&lt;/strong&gt; to address food shortages and improve living conditions post-independence.&lt;/li&gt;
		&lt;li data-end=&quot;2684&quot; data-start=&quot;2415&quot;&gt;It prioritized investments in &lt;strong&gt;dams, irrigation projects, and agricultural production&lt;/strong&gt;. For example, projects like &lt;strong&gt;Bhakra Nangal Dam&lt;/strong&gt; were initiated.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Second Five-Year Plan (1956-1961):&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;2860&quot; data-start=&quot;2735&quot;&gt;This plan emphasized the growth of &lt;strong&gt;heavy industries&lt;/strong&gt; and the expansion of the public sector to achieve self-reliance in industrial production.&lt;/li&gt;
		&lt;li data-end=&quot;3071&quot; data-start=&quot;2865&quot;&gt;Steel plants like &lt;strong&gt;Bhilai, Rourkela, and Durgapur&lt;/strong&gt; were established during this period, which became symbols of India&amp;#39;s industrial progress.&lt;/li&gt;
		&lt;li data-end=&quot;3250&quot; data-start=&quot;3076&quot;&gt;It also aimed to enhance the production of &lt;strong&gt;coal, power, and machinery&lt;/strong&gt; to support industrialization.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Third Five-Year Plan (1961-1966):&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;3402&quot; data-start=&quot;3301&quot;&gt;The Third Plan focused on &lt;strong&gt;self-reliance and poverty reduction&lt;/strong&gt;. It aimed to diversify the industrial base and increase agricultural production to meet the needs of the growing population.&lt;/li&gt;
		&lt;li data-end=&quot;3729&quot; data-start=&quot;3585&quot;&gt;However, the plan&amp;#39;s success was hampered by challenges like the &lt;strong&gt;Indo-China War (1962)&lt;/strong&gt; and the &lt;strong&gt;Indo-Pak War (1965)&lt;/strong&gt;, which diverted resources to defense.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Fourth Five-Year Plan (1969-1974):&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;3402&quot; data-start=&quot;3301&quot;&gt;The Fourth Plan focused on achieving &lt;strong&gt;economic stability&lt;/strong&gt; and reducing income inequality.&lt;/li&gt;
		&lt;li data-end=&quot;3580&quot; data-start=&quot;3407&quot;&gt;It aimed at improving agricultural productivity through the &lt;strong&gt;Green Revolution&lt;/strong&gt; and investing in power and transport infrastructure.&lt;/li&gt;
		&lt;li data-end=&quot;3729&quot; data-start=&quot;3585&quot;&gt;Emphasis was also placed on &lt;strong&gt;poverty alleviation programs&lt;/strong&gt; and ensuring social justice.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;The Mahalnobis Model:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;4636&quot; data-start=&quot;4411&quot;&gt;The Second Plan was based on the &lt;strong&gt;Mahalnobis Model&lt;/strong&gt;, developed by statistician &lt;strong&gt;Prasanta Chandra Mahalanobis&lt;/strong&gt;. This model emphasized the development of &lt;strong&gt;capital goods industries&lt;/strong&gt; like steel, machinery, and infrastructure as a pathway to economic growth.&lt;/li&gt;
		&lt;li data-end=&quot;4761&quot; data-start=&quot;4641&quot;&gt;The idea was to create a strong industrial base that would support other sectors of the economy, such as agriculture and services.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Significance of Heavy Industries:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;5043&quot; data-start=&quot;4817&quot;&gt;Heavy industries are crucial for producing &lt;strong&gt;capital goods&lt;/strong&gt; required for industrialization, such as machinery, transport equipment, and construction materials.&lt;/li&gt;
		&lt;li data-end=&quot;5259&quot; data-start=&quot;5048&quot;&gt;They contribute to &lt;strong&gt;job creation&lt;/strong&gt;, technological advancement, and the overall growth of the economy.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p data-end=&quot;57&quot; data-start=&quot;0&quot;&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;दूसरी योजना&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p data-end=&quot;57&quot; data-start=&quot;0&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;284&quot; data-start=&quot;78&quot;&gt;&lt;strong&gt;दूसरी पंचवर्षीय योजना (1956-1961)&lt;/strong&gt; ने भारत में &lt;strong&gt;भारी उद्योगों&lt;/strong&gt; के विकास पर प्रमुख जोर दिया। यह &lt;strong&gt;महालनोबिस मॉडल&lt;/strong&gt; पर आधारित थी, जिसने आर्थिक विकास प्राप्त करने की रणनीति के रूप में औद्योगीकरण को प्राथमिकता दी।&lt;/li&gt;
	&lt;li data-end=&quot;605&quot; data-start=&quot;482&quot;&gt;मुख्य ध्यान &lt;strong&gt;इस्पात, कोयला, सीमेंट और भारी मशीनरी&lt;/strong&gt; जैसे उद्योगों के विकास पर था, जिन्हें बुनियादी ढांचे के विकास और आर्थिक आत्मनिर्भरता के लिए आवश्यक माना जाता था।&lt;/li&gt;
	&lt;li data-end=&quot;692&quot; data-start=&quot;610&quot;&gt;इस योजना का उद्देश्य औद्योगिक विकास को बढ़ावा देने के लिए &lt;strong&gt;सार्वजनिक क्षेत्र के उद्यमों&lt;/strong&gt; की स्थापना को बढ़ावा देना था, क्योंकि उस अवधि के दौरान निजी पूंजी सीमित थी।&lt;/li&gt;
	&lt;li data-end=&quot;1041&quot; data-start=&quot;850&quot;&gt;भारी उद्योगों पर जोर को &lt;strong&gt;दीर्घकालिक आर्थिक विकास&lt;/strong&gt; के लिए एक मजबूत नींव बनाने और विदेशी आयात पर निर्भरता को कम करने के साधन के रूप में देखा गया।&lt;/li&gt;
	&lt;li data-end=&quot;1162&quot; data-start=&quot;1046&quot;&gt;इस योजना का उद्देश्य औद्योगिक उत्पादन को बढ़ावा देकर और औद्योगिक क्षेत्र में अधिक रोजगार के अवसर पैदा करके बेरोजगारी को कम करना और सामाजिक-आर्थिक स्थितियों में सुधार करना भी था।&lt;/li&gt;
	&lt;li data-end=&quot;1654&quot; data-start=&quot;1565&quot;&gt;&lt;em style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;इसलिए, दूसरी योजना ने भारी उद्योगों पर प्रमुख जोर दिया।&lt;/span&gt;&lt;/em&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;पहली पंचवर्षीय योजना (1951-1956):&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;2410&quot; data-start=&quot;2195&quot;&gt;पहली योजना में खाद्य कमी को दूर करने और स्वतंत्रता के बाद जीवन स्तर में सुधार के लिए &lt;strong&gt;कृषि, सिंचाई और ग्रामीण विकास&lt;/strong&gt; पर ध्यान केंद्रित किया गया।&lt;/li&gt;
		&lt;li data-end=&quot;2684&quot; data-start=&quot;2415&quot;&gt;इसने &lt;strong&gt;बांधों, सिंचाई परियोजनाओं और कृषि उत्पादन&lt;/strong&gt; में निवेश को प्राथमिकता दी। उदाहरण के लिए, &lt;strong&gt;भाखड़ा नांगल बांध&lt;/strong&gt; जैसी परियोजनाएं शुरू की गईं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;दूसरी पंचवर्षीय योजना (1956-1961):&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;2860&quot; data-start=&quot;2735&quot;&gt;इस योजना ने औद्योगिक उत्पादन में आत्मनिर्भरता प्राप्त करने के लिए &lt;strong&gt;भारी उद्योगों&lt;/strong&gt; के विकास और सार्वजनिक क्षेत्र के विस्तार पर जोर दिया।&lt;/li&gt;
		&lt;li data-end=&quot;3071&quot; data-start=&quot;2865&quot;&gt;इस अवधि के दौरान &lt;strong&gt;भिलाई, राउरकेला और दुर्गापुर&lt;/strong&gt; जैसे इस्पात संयंत्र स्थापित किए गए, जो भारत की औद्योगिक प्रगति के प्रतीक बन गए।&lt;/li&gt;
		&lt;li data-end=&quot;3250&quot; data-start=&quot;3076&quot;&gt;इसका उद्देश्य औद्योगीकरण का समर्थन करने के लिए &lt;strong&gt;कोयला, बिजली और मशीनरी&lt;/strong&gt; के उत्पादन को बढ़ाना भी था।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;तीसरी पंचवर्षीय योजना (1961-1966):&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;3402&quot; data-start=&quot;3301&quot;&gt;तीसरी योजना ने &lt;strong&gt;आत्मनिर्भरता और गरीबी कम करने&lt;/strong&gt; पर ध्यान केंद्रित किया। इसका उद्देश्य बढ़ती आबादी की जरूरतों को पूरा करने के लिए औद्योगिक आधार में विविधता लाना और कृषि उत्पादन बढ़ाना था।&lt;/li&gt;
		&lt;li data-end=&quot;3729&quot; data-start=&quot;3585&quot;&gt;हालांकि, योजना की सफलता में &lt;strong&gt;भारत-चीन युद्ध (1962)&lt;/strong&gt; और &lt;strong&gt;भारत-पाक युद्ध (1965)&lt;/strong&gt; जैसी चुनौतियों से बाधा आई, जिसने संसाधनों को रक्षा की ओर मोड़ दिया।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;चौथी पंचवर्षीय योजना (1969-1974):&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;3402&quot; data-start=&quot;3301&quot;&gt;चौथी योजना ने &lt;strong&gt;आर्थिक स्थिरता&lt;/strong&gt; प्राप्त करने और आय असमानता को कम करने पर ध्यान केंद्रित किया।&lt;/li&gt;
		&lt;li data-end=&quot;3580&quot; data-start=&quot;3407&quot;&gt;इसका उद्देश्य &lt;strong&gt;हरित क्रांति&lt;/strong&gt; के माध्यम से कृषि उत्पादकता में सुधार करना और बिजली और परिवहन बुनियादी ढांचे में निवेश करना था।&lt;/li&gt;
		&lt;li data-end=&quot;3729&quot; data-start=&quot;3585&quot;&gt;&lt;strong&gt;गरीबी उन्मूलन कार्यक्रमों&lt;/strong&gt; और सामाजिक न्याय सुनिश्चित करने पर भी जोर दिया गया।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;महालनोबिस मॉडल:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;4636&quot; data-start=&quot;4411&quot;&gt;दूसरी योजना &lt;strong&gt;महालनोबिस मॉडल&lt;/strong&gt; पर आधारित थी, जिसे सांख्यिकीविद् &lt;strong&gt;प्रशांत चंद्र महालनोबिस&lt;/strong&gt; ने विकसित किया था। इस मॉडल ने आर्थिक विकास के मार्ग के रूप में इस्पात, मशीनरी और बुनियादी ढांचे जैसे &lt;strong&gt;पूंजीगत वस्तुओं के उद्योगों&lt;/strong&gt; के विकास पर जोर दिया।&lt;/li&gt;
		&lt;li data-end=&quot;4761&quot; data-start=&quot;4641&quot;&gt;विचार एक मजबूत औद्योगिक आधार बनाना था जो अर्थव्यवस्था के अन्य क्षेत्रों, जैसे कृषि और सेवाओं का समर्थन करेगा।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;भारी उद्योगों का महत्व:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;5043&quot; data-start=&quot;4817&quot;&gt;भारी उद्योग औद्योगीकरण के लिए आवश्यक &lt;strong&gt;पूंजीगत वस्तुओं&lt;/strong&gt; के उत्पादन के लिए महत्वपूर्ण हैं, जैसे मशीनरी, परिवहन उपकरण और निर्माण सामग्री।&lt;/li&gt;
		&lt;li data-end=&quot;5259&quot; data-start=&quot;5048&quot;&gt;वे &lt;strong&gt;रोजगार सृजन&lt;/strong&gt;, तकनीकी उन्नति और अर्थव्यवस्था के समग्र विकास में योगदान करते हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p data-end=&quot;57&quot; data-start=&quot;0&quot;&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Norman Pritchard&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p data-end=&quot;57&quot; data-start=&quot;0&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;284&quot; data-start=&quot;78&quot;&gt;&lt;strong&gt;Norman Pritchard&lt;/strong&gt; was the first Indian athlete to win an Olympic medal at the &lt;strong&gt;1900 Paris Olympics&lt;/strong&gt;.&lt;/li&gt;
	&lt;li data-end=&quot;482&quot; data-start=&quot;284&quot;&gt;He won &lt;strong&gt;two silver medals&lt;/strong&gt; in the &lt;strong&gt;200 meters sprint&lt;/strong&gt; and the &lt;strong&gt;200 meters hurdles&lt;/strong&gt; events.&lt;/li&gt;
	&lt;li data-end=&quot;692&quot; data-start=&quot;482&quot;&gt;Pritchard&amp;#39;s achievements marked a significant milestone in Indian sports history as he was the first Indian-born athlete to compete and win at the Olympics.&lt;/li&gt;
	&lt;li data-end=&quot;850&quot; data-start=&quot;692&quot;&gt;He competed under the banner of &lt;strong&gt;British India&lt;/strong&gt;, as India was under British rule at the time.&lt;/li&gt;
	&lt;li data-end=&quot;1046&quot; data-start=&quot;850&quot;&gt;Despite controversies surrounding whether he represented India or Britain, the &lt;strong&gt;International Olympic Committee (IOC)&lt;/strong&gt; officially recognizes him as an Indian athlete.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Norman Pritchard&amp;#39;s Background:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;1500&quot; data-start=&quot;1047&quot;&gt;Born in &lt;strong&gt;Calcutta (now Kolkata)&lt;/strong&gt; in &lt;strong&gt;1875&lt;/strong&gt;, Pritchard was a British citizen residing in India.&lt;/li&gt;
		&lt;li data-end=&quot;1700&quot; data-start=&quot;1505&quot;&gt;He was an accomplished athlete and was also known for his contributions to football and cricket in India.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Events at 1900 Paris Olympics:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;1900&quot; data-start=&quot;1705&quot;&gt;The &lt;strong&gt;200 meters sprint&lt;/strong&gt; was one of the most competitive events, where Pritchard secured a silver medal behind &lt;strong&gt;Walter Tewksbury&lt;/strong&gt; of the USA.&lt;/li&gt;
		&lt;li data-end=&quot;2100&quot; data-start=&quot;1905&quot;&gt;In the &lt;strong&gt;200 meters hurdles&lt;/strong&gt;, Pritchard earned his second silver medal, demonstrating his prowess in track and field events.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Legacy:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;2300&quot; data-start=&quot;2105&quot;&gt;Norman Pritchard&amp;#39;s success paved the way for future Indian athletes and inspired participation in global sports events.&lt;/li&gt;
		&lt;li data-end=&quot;2500&quot; data-start=&quot;2305&quot;&gt;He later moved to the USA, where he became a successful actor in Hollywood, using the stage name &lt;strong&gt;Norman Trevor&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Milkha Singh:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;2700&quot; data-start=&quot;2505&quot;&gt;Milkha Singh, also known as the &amp;quot;Flying Sikh,&amp;quot; represented India in the &lt;strong&gt;1960 Rome Olympics&lt;/strong&gt; but did not win any medals.&lt;/li&gt;
		&lt;li data-end=&quot;2900&quot; data-start=&quot;2705&quot;&gt;He was a celebrated Indian sprinter who narrowly missed a bronze medal in the 400 meters event.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;K. D. Jadhav:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;3100&quot; data-start=&quot;2905&quot;&gt;Khashaba Dadasaheb Jadhav was the first Indian to win an individual Olympic medal (bronze) in &lt;strong&gt;wrestling&lt;/strong&gt; at the &lt;strong&gt;1952 Helsinki Olympics&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Dhyan Chand:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;3300&quot; data-start=&quot;3105&quot;&gt;Dhyan Chand, known as the &amp;quot;&lt;strong&gt;Wizard of Hockey&lt;/strong&gt;,&amp;quot; led India to &lt;strong&gt;three Olympic gold medals&lt;/strong&gt; in &lt;strong&gt;1928, 1932, and 1936&lt;/strong&gt;.&lt;/li&gt;
		&lt;li data-end=&quot;3500&quot; data-start=&quot;3305&quot;&gt;However, field hockey was a team event, and he did not win any individual medals.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p data-end=&quot;57&quot; data-start=&quot;0&quot;&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;नॉर्मन प्रिचर्ड&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p data-end=&quot;57&quot; data-start=&quot;0&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;284&quot; data-start=&quot;78&quot;&gt;&lt;strong&gt;नॉर्मन प्रिचर्ड&lt;/strong&gt; &lt;strong&gt;1900 के पेरिस ओलंपिक&lt;/strong&gt; में ओलंपिक पदक जीतने वाले पहले भारतीय एथलीट थे।&lt;/li&gt;
	&lt;li data-end=&quot;482&quot; data-start=&quot;284&quot;&gt;उन्होंने &lt;strong&gt;200 मीटर स्प्रिंट&lt;/strong&gt; और &lt;strong&gt;200 मीटर बाधा दौड़&lt;/strong&gt; स्पर्धाओं में &lt;strong&gt;दो रजत पदक&lt;/strong&gt; जीते।&lt;/li&gt;
	&lt;li data-end=&quot;692&quot; data-start=&quot;482&quot;&gt;प्रिचर्ड की उपलब्धियों ने भारतीय खेल इतिहास में एक महत्वपूर्ण मील का पत्थर स्थापित किया क्योंकि वह ओलंपिक में प्रतिस्पर्धा करने और जीतने वाले पहले भारतीय मूल के एथलीट थे।&lt;/li&gt;
	&lt;li data-end=&quot;850&quot; data-start=&quot;692&quot;&gt;उन्होंने &lt;strong&gt;ब्रिटिश भारत&lt;/strong&gt; के बैनर तले प्रतिस्पर्धा की, क्योंकि उस समय भारत ब्रिटिश शासन के अधीन था।&lt;/li&gt;
	&lt;li data-end=&quot;1046&quot; data-start=&quot;850&quot;&gt;इस बात को लेकर विवादों के बावजूद कि उन्होंने भारत या ब्रिटेन का प्रतिनिधित्व किया, &lt;strong&gt;अंतर्राष्ट्रीय ओलंपिक समिति (आईओसी)&lt;/strong&gt; आधिकारिक तौर पर उन्हें एक भारतीय एथलीट के रूप में मान्यता देती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;नॉर्मन प्रिचर्ड की पृष्ठभूमि:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;1500&quot; data-start=&quot;1047&quot;&gt;&lt;strong&gt;1875&lt;/strong&gt; में &lt;strong&gt;कलकत्ता (अब कोलकाता)&lt;/strong&gt; में जन्मे, प्रिचर्ड भारत में रहने वाले एक ब्रिटिश नागरिक थे।&lt;/li&gt;
		&lt;li data-end=&quot;1700&quot; data-start=&quot;1505&quot;&gt;वह एक कुशल एथलीट थे और भारत में फुटबॉल और क्रिकेट में उनके योगदान के लिए भी जाने जाते थे।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;1900 पेरिस ओलंपिक में कार्यक्रम:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;1900&quot; data-start=&quot;1705&quot;&gt;&lt;strong&gt;200 मीटर स्प्रिंट&lt;/strong&gt; सबसे प्रतिस्पर्धी स्पर्धाओं में से एक थी, जहाँ प्रिचर्ड ने संयुक्त राज्य अमेरिका के &lt;strong&gt;वाल्टर टेवक्सबरी&lt;/strong&gt; के पीछे रजत पदक हासिल किया।&lt;/li&gt;
		&lt;li data-end=&quot;2100&quot; data-start=&quot;1905&quot;&gt;&lt;strong&gt;200 मीटर बाधा दौड़&lt;/strong&gt; में, प्रिचर्ड ने अपना दूसरा रजत पदक अर्जित किया, जो ट्रैक और फील्ड स्पर्धाओं में उनकी क्षमता का प्रदर्शन करता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;विरासत:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;2300&quot; data-start=&quot;2105&quot;&gt;नॉर्मन प्रिचर्ड की सफलता ने भविष्य के भारतीय एथलीटों के लिए मार्ग प्रशस्त किया और वैश्विक खेल आयोजनों में भागीदारी को प्रेरित किया।&lt;/li&gt;
		&lt;li data-end=&quot;2500&quot; data-start=&quot;2305&quot;&gt;बाद में वे संयुक्त राज्य अमेरिका चले गए, जहाँ वे हॉलीवुड में एक सफल अभिनेता बन गए, उन्होंने &lt;strong&gt;नॉर्मन ट्रेवर&lt;/strong&gt; नाम का इस्तेमाल किया।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;मिल्खा सिंह:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;2700&quot; data-start=&quot;2505&quot;&gt;मिल्खा सिंह, जिन्हें &amp;quot;फ्लाइंग सिख&amp;quot; के नाम से भी जाना जाता है, ने &lt;strong&gt;1960 के रोम ओलंपिक&lt;/strong&gt; में भारत का प्रतिनिधित्व किया, लेकिन कोई पदक नहीं जीता।&lt;/li&gt;
		&lt;li data-end=&quot;2900&quot; data-start=&quot;2705&quot;&gt;वह एक प्रसिद्ध भारतीय स्प्रिंटर थे जो 400 मीटर स्पर्धा में कांस्य पदक से चूक गए थे।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;के. डी. जाधव:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;3100&quot; data-start=&quot;2905&quot;&gt;खाशाबा दादासाहेब जाधव &lt;strong&gt;1952 के हेलसिंकी ओलंपिक&lt;/strong&gt; में &lt;strong&gt;कुश्ती&lt;/strong&gt; में व्यक्तिगत ओलंपिक पदक (कांस्य) जीतने वाले पहले भारतीय थे।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;ध्यानचंद:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;3300&quot; data-start=&quot;3105&quot;&gt;ध्यानचंद, जिन्हें &amp;quot;&lt;strong&gt;हॉकी के जादूगर&lt;/strong&gt;&amp;quot; के रूप में जाना जाता है, ने भारत को &lt;strong&gt;1928, 1932 और 1936&lt;/strong&gt; में &lt;strong&gt;तीन ओलंपिक स्वर्ण पदक&lt;/strong&gt; दिलाए।&lt;/li&gt;
		&lt;li data-end=&quot;3500&quot; data-start=&quot;3305&quot;&gt;हालांकि, फील्ड हॉकी एक टीम स्पर्धा थी, और उन्होंने कोई व्यक्तिगत पदक नहीं जीता।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The Correct answer is &lt;u&gt;&lt;strong&gt;Directive Principles of State Policy&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: (33, 37, 41);&quot;&gt;
	&lt;li&gt;&lt;strong&gt;Article 50&lt;/strong&gt; of the Indian Constitution falls under the &lt;strong&gt;Directive Principles of State Policy&lt;/strong&gt;, which is enshrined in &lt;strong&gt;Part IV&lt;/strong&gt; of the Constitution.&lt;/li&gt;
	&lt;li&gt;The article directs the state to take steps to &lt;strong&gt;separate the judiciary from the executive&lt;/strong&gt; in the public services of the state.&lt;/li&gt;
	&lt;li&gt;The &lt;strong&gt;Directive Principles of State Policy&lt;/strong&gt; act as guidelines for the state in the governance of the country and aim to establish a &lt;strong&gt;welfare state&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;These principles are &lt;strong&gt;non-justiciable&lt;/strong&gt;, meaning they are not enforceable by any court, but they are fundamental in the governance of the country.&lt;/li&gt;
	&lt;li&gt;The inclusion of Directive Principles in the Constitution was inspired by the &lt;strong&gt;Irish Constitution&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The main objective of Article 50 is to ensure the &lt;strong&gt;independence of the judiciary&lt;/strong&gt;, which is crucial for the functioning of a fair and impartial judicial system.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Fundamental Rights&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;The &lt;strong&gt;Fundamental Rights&lt;/strong&gt; are enshrined in &lt;strong&gt;Part III&lt;/strong&gt; of the Indian Constitution and include Articles &lt;strong&gt;12 to 35&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;These rights are &lt;strong&gt;justiciable&lt;/strong&gt;, meaning individuals can approach the courts if their rights are violated.&lt;/li&gt;
		&lt;li&gt;Examples include the &lt;strong&gt;Right to Equality&lt;/strong&gt;, &lt;strong&gt;Right to Freedom&lt;/strong&gt;, &lt;strong&gt;Right against Exploitation&lt;/strong&gt;, and &lt;strong&gt;Right to Constitutional Remedies&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Fundamental Duties&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;The &lt;strong&gt;Fundamental Duties&lt;/strong&gt; are enshrined in &lt;strong&gt;Article 51A&lt;/strong&gt; under &lt;strong&gt;Part IVA&lt;/strong&gt; of the Constitution.&lt;/li&gt;
		&lt;li&gt;They were added by the &lt;strong&gt;42nd Amendment Act, 1976&lt;/strong&gt; based on the recommendations of the &lt;strong&gt;Swaran Singh Committee&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;Examples include respecting the &lt;strong&gt;National Flag&lt;/strong&gt;, protecting the &lt;strong&gt;environment&lt;/strong&gt;, and safeguarding the &lt;strong&gt;cultural heritage of India&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Preamble&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;The &lt;strong&gt;Preamble&lt;/strong&gt; serves as the &lt;strong&gt;introduction&lt;/strong&gt; to the Constitution and states the objectives such as &lt;strong&gt;Justice&lt;/strong&gt;, &lt;strong&gt;Liberty&lt;/strong&gt;, &lt;strong&gt;Equality&lt;/strong&gt;, and &lt;strong&gt;Fraternity&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;It is based on the &lt;strong&gt;Objective Resolution&lt;/strong&gt; moved by &lt;strong&gt;Jawaharlal Nehru&lt;/strong&gt; in the Constituent Assembly.&lt;/li&gt;
		&lt;li&gt;Although the Preamble is not enforceable in a court of law, it is used as a guide to understand the &lt;strong&gt;spirit of the Constitution&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;राज्य नीति के निदेशक सिद्धांत&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: (33, 37, 41);&quot;&gt;
	&lt;li&gt;भारतीय संविधान का &lt;strong&gt;अनुच्छेद 50&lt;/strong&gt; &lt;strong&gt;राज्य नीति के निदेशक सिद्धांतों&lt;/strong&gt; के अंतर्गत आता है, जो संविधान के &lt;strong&gt;भाग IV&lt;/strong&gt; में निहित है।&lt;/li&gt;
	&lt;li&gt;यह अनुच्छेद राज्य को राज्य की सार्वजनिक सेवाओं में &lt;strong&gt;न्यायपालिका को कार्यपालिका से अलग&lt;/strong&gt; करने के लिए कदम उठाने का निर्देश देता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;राज्य नीति के निदेशक सिद्धांत&lt;/strong&gt; देश के शासन में राज्य के लिए दिशानिर्देश के रूप में कार्य करते हैं और इसका उद्देश्य एक &lt;strong&gt;कल्याणकारी राज्य&lt;/strong&gt; की स्थापना करना है।&lt;/li&gt;
	&lt;li&gt;ये सिद्धांत &lt;strong&gt;गैर-न्यायसंगत&lt;/strong&gt; हैं, जिसका अर्थ है कि वे किसी भी अदालत द्वारा लागू करने योग्य नहीं हैं, लेकिन वे देश के शासन में मौलिक हैं।&lt;/li&gt;
	&lt;li&gt;संविधान में निदेशक सिद्धांतों को शामिल करने की प्रेरणा &lt;strong&gt;आयरिश संविधान&lt;/strong&gt; से मिली थी।&lt;/li&gt;
	&lt;li&gt;अनुच्छेद 50 का मुख्य उद्देश्य &lt;strong&gt;न्यायपालिका की स्वतंत्रता&lt;/strong&gt; सुनिश्चित करना है, जो एक निष्पक्ष और निष्पक्ष न्यायिक प्रणाली के कामकाज के लिए महत्वपूर्ण है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;मौलिक अधिकार&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;मौलिक अधिकार&lt;/strong&gt; भारतीय संविधान के &lt;strong&gt;भाग III&lt;/strong&gt; में निहित हैं और इसमें &lt;strong&gt;अनुच्छेद 12 से 35&lt;/strong&gt; शामिल हैं।&lt;/li&gt;
		&lt;li&gt;ये अधिकार &lt;strong&gt;न्यायसंगत&lt;/strong&gt; हैं, जिसका अर्थ है कि यदि उनके अधिकारों का उल्लंघन होता है तो व्यक्ति अदालतों का दरवाजा खटखटा सकते हैं।&lt;/li&gt;
		&lt;li&gt;उदाहरणों में &lt;strong&gt;समानता का अधिकार&lt;/strong&gt;, &lt;strong&gt;स्वतंत्रता का अधिकार&lt;/strong&gt;, &lt;strong&gt;शोषण के खिलाफ अधिकार&lt;/strong&gt; और &lt;strong&gt;संवैधानिक उपचार का अधिकार&lt;/strong&gt; शामिल हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;मौलिक कर्तव्य&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;मौलिक कर्तव्य&lt;/strong&gt; संविधान के &lt;strong&gt;भाग IVA&lt;/strong&gt; के तहत &lt;strong&gt;अनुच्छेद 51A&lt;/strong&gt; में निहित हैं।&lt;/li&gt;
		&lt;li&gt;इन्हें &lt;strong&gt;स्वर्ण सिंह समिति&lt;/strong&gt; की सिफारिशों के आधार पर &lt;strong&gt;42वें संशोधन अधिनियम, 1976&lt;/strong&gt; द्वारा जोड़ा गया था।&lt;/li&gt;
		&lt;li&gt;उदाहरणों में &lt;strong&gt;राष्ट्रीय ध्वज&lt;/strong&gt; का सम्मान करना, &lt;strong&gt;पर्यावरण&lt;/strong&gt; की रक्षा करना और &lt;strong&gt;भारत की सांस्कृतिक विरासत&lt;/strong&gt; की रक्षा करना शामिल है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;प्रस्तावना&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;प्रस्तावना&lt;/strong&gt; संविधान के &lt;strong&gt;परिचय&lt;/strong&gt; के रूप में कार्य करती है और &lt;strong&gt;न्याय&lt;/strong&gt;, &lt;strong&gt;स्वतंत्रता&lt;/strong&gt;, &lt;strong&gt;समानता&lt;/strong&gt; और &lt;strong&gt;बंधुत्व&lt;/strong&gt; जैसे उद्देश्यों को बताती है।&lt;/li&gt;
		&lt;li&gt;यह संविधान सभा में &lt;strong&gt;जवाहरलाल नेहरू&lt;/strong&gt; द्वारा पेश किए गए &lt;strong&gt;उद्देश्य संकल्प&lt;/strong&gt; पर आधारित है।&lt;/li&gt;
		&lt;li&gt;यद्यपि प्रस्तावना कानून की अदालत में लागू करने योग्य नहीं है, लेकिन इसका उपयोग &lt;strong&gt;संविधान की भावना&lt;/strong&gt; को समझने के लिए एक मार्गदर्शक के रूप में किया जाता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p data-end=&quot;&quot; data-start=&quot;&quot;&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Troposphere &amp;ndash; Weather&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;span align-items:=&quot;&quot; display:=&quot;&quot; gap:=&quot;&quot; style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;Troposphere:&lt;/strong&gt; The troposphere is the &lt;strong&gt;lowest layer of Earth&amp;#39;s atmosphere&lt;/strong&gt; where &lt;strong&gt;weather phenomena&lt;/strong&gt; such as clouds, rain, snow, and storms occur. This layer extends from the Earth&amp;#39;s surface up to an average altitude of about &lt;strong&gt;8 to 15 kilometers&lt;/strong&gt;. Hence, the statement &amp;quot;&lt;strong&gt;Troposphere - Weather&lt;/strong&gt;&amp;quot; is &lt;em&gt;correct&lt;/em&gt;.&lt;/li&gt;
	&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;Thermosphere:&lt;/strong&gt; This is the layer above the mesosphere, extending from &lt;strong&gt;about 80 kilometers to 700 kilometers&lt;/strong&gt;. It is characterized by high temperatures due to the absorption of solar radiation. However, the thermosphere does &lt;strong&gt;not contain ozone&lt;/strong&gt;. Hence, the statement &amp;quot;&lt;strong&gt;Thermosphere - Ozone&lt;/strong&gt;&amp;quot; is &lt;em&gt;incorrect&lt;/em&gt;.&lt;/li&gt;
	&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;Mesosphere:&lt;/strong&gt; The mesosphere lies between 50 and 80 kilometers above the Earth&amp;#39;s surface. It is known as the &lt;strong&gt;coldest atmospheric layer&lt;/strong&gt;. This layer does not support satellites as they orbit much higher, in the exosphere and thermosphere. Hence, the statement &amp;quot;&lt;strong&gt;Mesosphere - Satellites&lt;/strong&gt;&amp;quot; is &lt;em&gt;incorrect&lt;/em&gt;.&lt;/li&gt;
	&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;Stratosphere:&lt;/strong&gt; The stratosphere extends from about 10 to 50 kilometers above the Earth&amp;#39;s surface. This layer contains the &lt;strong&gt;ozone layer&lt;/strong&gt;, which absorbs harmful ultraviolet radiation. Meteors burn up in the mesosphere, not the stratosphere. Hence, the statement &amp;quot;&lt;strong&gt;Stratosphere - Meteors&lt;/strong&gt;&amp;quot; is &lt;em&gt;incorrect&lt;/em&gt;.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span align-items:=&quot;&quot; display:=&quot;&quot; gap:=&quot;&quot; style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Troposphere:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;The troposphere is the &lt;strong&gt;densest atmospheric layer&lt;/strong&gt;, containing approximately &lt;strong&gt;75% of the atmosphere&amp;#39;s mass&lt;/strong&gt; and most of the water vapor.&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;Temperature decreases&lt;/strong&gt; with altitude in the troposphere at an average rate of &lt;strong&gt;6.5&amp;deg;C per kilometer&lt;/strong&gt;.&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;Weather systems&lt;/strong&gt; such as cyclones, thunderstorms, and precipitation occur in this layer due to its interaction with the Earth&amp;#39;s surface and water bodies.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Thermosphere:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;The thermosphere contains layers like the &lt;strong&gt;ionosphere&lt;/strong&gt;, which plays a crucial role in radio communication by reflecting radio waves back to Earth.&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;Temperatures in the thermosphere&lt;/strong&gt; can rise to 2,500&amp;deg;C or higher, but due to the low density of particles, this heat cannot be felt.&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;Auroras, such as the &lt;strong&gt;northern and southern lights&lt;/strong&gt;, occur in this layer due to interactions between solar winds and the Earth&amp;#39;s magnetic field.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Mesosphere:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;Meteors typically burn up in the mesosphere due to friction with atmospheric particles, creating the phenomenon of &lt;strong&gt;shooting stars&lt;/strong&gt;.&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;Temperature decreases&lt;/strong&gt; with altitude in the mesosphere, reaching as low as &lt;strong&gt;-90&amp;deg;C&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Stratosphere:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;The ozone layer in the stratosphere absorbs ultraviolet radiation, protecting living organisms from harmful UV rays.&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;Jet aircraft&lt;/strong&gt; often fly in the lower stratosphere to avoid turbulence in the troposphere.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span align-items:=&quot;&quot; display:=&quot;&quot; gap:=&quot;&quot; style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Order of Atmospheric Layers:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;Troposphere&lt;/strong&gt; (closest to Earth) &amp;rarr; &lt;strong&gt;Stratosphere&lt;/strong&gt; &amp;rarr; &lt;strong&gt;Mesosphere&lt;/strong&gt; &amp;rarr; &lt;strong&gt;Thermosphere&lt;/strong&gt; &amp;rarr; &lt;strong&gt;Exosphere&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Applications of Atmospheric Layers:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;Troposphere:&lt;/strong&gt; Weather forecasting and aviation.&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;Stratosphere:&lt;/strong&gt; Protection from UV radiation, jet travel.&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;Thermosphere:&lt;/strong&gt; Satellite orbits, auroras.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p data-end=&quot;&quot; data-start=&quot;&quot;&gt;सही उत्तर है &lt;u&gt;&lt;strong&gt;क्षोभमंडल - मौसम&lt;/strong&gt;&lt;/u&gt;।&lt;/p&gt;

&lt;p data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;span align-items:=&quot;&quot; display:=&quot;&quot; gap:=&quot;&quot; style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;मुख्य बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;क्षोभमंडल:&lt;/strong&gt; क्षोभमंडल &lt;strong&gt;पृथ्वी के वायुमंडल की सबसे निचली परत&lt;/strong&gt; है जहाँ बादल, बारिश, बर्फ और तूफान जैसी &lt;strong&gt;मौसम संबंधी घटनाएं&lt;/strong&gt; होती हैं। यह परत पृथ्वी की सतह से औसतन लगभग &lt;strong&gt;8 से 15 किलोमीटर&lt;/strong&gt; की ऊंचाई तक फैली हुई है। इसलिए, कथन &amp;quot;&lt;strong&gt;क्षोभमंडल - मौसम&lt;/strong&gt;&amp;quot; &lt;em&gt;सही&lt;/em&gt; है।&lt;/li&gt;
	&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;तापमंडल:&lt;/strong&gt; यह मध्यमंडल के ऊपर की परत है, जो &lt;strong&gt;लगभग 80 किलोमीटर से 700 किलोमीटर&lt;/strong&gt; तक फैली हुई है। यह सौर विकिरण के अवशोषण के कारण उच्च तापमान की विशेषता है। हालाँकि, तापमंडल में &lt;strong&gt;ओजोन नहीं होता&lt;/strong&gt; है। इसलिए, कथन &amp;quot;&lt;strong&gt;तापमंडल - ओजोन&lt;/strong&gt;&amp;quot; &lt;em&gt;गलत&lt;/em&gt; है।&lt;/li&gt;
	&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;मध्यमंडल:&lt;/strong&gt; मध्यमंडल पृथ्वी की सतह से 50 से 80 किलोमीटर के बीच स्थित है। इसे &lt;strong&gt;सबसे ठंडी वायुमंडलीय परत&lt;/strong&gt; के रूप में जाना जाता है। यह परत उपग्रहों का समर्थन नहीं करती है क्योंकि वे बहुत अधिक ऊंचाई पर, बहिर्मंडल और तापमंडल में परिक्रमा करते हैं। इसलिए, कथन &amp;quot;&lt;strong&gt;मध्यमंडल - उपग्रह&lt;/strong&gt;&amp;quot; &lt;em&gt;गलत&lt;/em&gt; है।&lt;/li&gt;
	&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;समतापमंडल:&lt;/strong&gt; समतापमंडल पृथ्वी की सतह से लगभग 10 से 50 किलोमीटर ऊपर तक फैला हुआ है। इस परत में &lt;strong&gt;ओजोन परत&lt;/strong&gt; होती है, जो हानिकारक पराबैंगनी विकिरण को अवशोषित करती है। उल्कापिंड समतापमंडल में नहीं, बल्कि मध्यमंडल में जलते हैं। इसलिए, कथन &amp;quot;&lt;strong&gt;समतापमंडल - उल्कापिंड&lt;/strong&gt;&amp;quot; &lt;em&gt;गलत&lt;/em&gt; है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span align-items:=&quot;&quot; display:=&quot;&quot; gap:=&quot;&quot; style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;अतिरिक्त जानकारी&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;क्षोभमंडल:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;क्षोभमंडल &lt;strong&gt;सबसे घनी वायुमंडलीय परत&lt;/strong&gt; है, जिसमें वायुमंडल के द्रव्यमान का लगभग &lt;strong&gt;75%&lt;/strong&gt; और अधिकांश जल वाष्प होता है।&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;क्षोभमंडल में ऊंचाई के साथ &lt;strong&gt;तापमान घटता है&lt;/strong&gt;, औसतन &lt;strong&gt;6.5&amp;deg;C प्रति किलोमीटर&lt;/strong&gt; की दर से।&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;पृथ्वी की सतह और जल निकायों के साथ इसकी परस्पर क्रिया के कारण इस परत में चक्रवात, गरज और वर्षा जैसी &lt;strong&gt;मौसम प्रणालियाँ&lt;/strong&gt; होती हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;तापमंडल:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;तापमंडल में &lt;strong&gt;आयनमंडल&lt;/strong&gt; जैसी परतें होती हैं, जो रेडियो तरंगों को वापस पृथ्वी पर परावर्तित करके रेडियो संचार में महत्वपूर्ण भूमिका निभाती हैं।&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;तापमंडल में तापमान&lt;/strong&gt; 2,500&amp;deg;C या उससे अधिक तक बढ़ सकता है, लेकिन कणों के कम घनत्व के कारण, इस गर्मी को महसूस नहीं किया जा सकता है।&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;सौर हवाओं और पृथ्वी के चुंबकीय क्षेत्र के बीच परस्पर क्रिया के कारण इस परत में &lt;strong&gt;उत्तरी और दक्षिणी रोशनी&lt;/strong&gt; जैसे अरोरा होते हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;मध्यमंडल:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;वायुमंडलीय कणों के साथ घर्षण के कारण उल्कापिंड आमतौर पर मध्यमंडल में जल जाते हैं, जिससे &lt;strong&gt;टूटते तारों&lt;/strong&gt; की घटना होती है।&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;मध्यमंडल में ऊंचाई के साथ &lt;strong&gt;तापमान घटता है&lt;/strong&gt;, जो &lt;strong&gt;-90&amp;deg;C&lt;/strong&gt; जितना कम हो जाता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;समतापमंडल:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;समतापमंडल में ओजोन परत पराबैंगनी विकिरण को अवशोषित करती है, जिससे जीवित जीवों को हानिकारक यूवी किरणों से बचाया जाता है।&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;जेट विमान&lt;/strong&gt; अक्सर क्षोभमंडल में अशांति से बचने के लिए निचले समतापमंडल में उड़ान भरते हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span align-items:=&quot;&quot; display:=&quot;&quot; gap:=&quot;&quot; style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;महत्वपूर्ण बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;वायुमंडलीय परतों का क्रम:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;क्षोभमंडल&lt;/strong&gt; (पृथ्वी के सबसे करीब) &amp;rarr; &lt;strong&gt;समतापमंडल&lt;/strong&gt; &amp;rarr; &lt;strong&gt;मध्यमंडल&lt;/strong&gt; &amp;rarr; &lt;strong&gt;तापमंडल&lt;/strong&gt; &amp;rarr; &lt;strong&gt;बहिर्मंडल&lt;/strong&gt;।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;वायुमंडलीय परतों के अनुप्रयोग:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;क्षोभमंडल:&lt;/strong&gt; मौसम का पूर्वानुमान और विमानन।&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;समतापमंडल:&lt;/strong&gt; यूवी विकिरण से सुरक्षा, जेट यात्रा।&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;तापमंडल:&lt;/strong&gt; उपग्रह कक्षाएँ, अरोरा।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p data-end=&quot;57&quot; data-start=&quot;0&quot;&gt;The correct answer is &lt;u&gt;&lt;strong&gt;42nd Amendment&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p data-end=&quot;57&quot; data-start=&quot;0&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;284&quot; data-start=&quot;78&quot;&gt;The &lt;strong&gt;42nd Amendment Act&lt;/strong&gt;, enacted in &lt;strong&gt;1976&lt;/strong&gt;, is often referred to as the &lt;strong&gt;&amp;quot;Mini-Constitution&amp;quot;&lt;/strong&gt; due to the extensive changes it brought to the Indian Constitution.&lt;/li&gt;
	&lt;li data-end=&quot;605&quot; data-start=&quot;482&quot;&gt;It was passed during the tenure of &lt;strong&gt;Prime Minister Indira Gandhi&lt;/strong&gt; during the period of the Emergency in India (1975-1977).&lt;/li&gt;
	&lt;li data-end=&quot;692&quot; data-start=&quot;610&quot;&gt;The amendment introduced significant changes to the &lt;strong&gt;Preamble&lt;/strong&gt;, the &lt;strong&gt;Fundamental Duties&lt;/strong&gt;, and the &lt;strong&gt;Directive Principles of State Policy&lt;/strong&gt; (DPSP), among other parts of the Constitution.&lt;/li&gt;
	&lt;li data-end=&quot;1041&quot; data-start=&quot;850&quot;&gt;The Preamble was amended to include the terms &lt;strong&gt;&amp;quot;Socialist&amp;quot;&lt;/strong&gt;, &lt;strong&gt;&amp;quot;Secular&amp;quot;&lt;/strong&gt;, and &lt;strong&gt;&amp;quot;Integrity&amp;quot;&lt;/strong&gt;, thereby emphasizing the secular and socialist nature of the Indian state.&lt;/li&gt;
	&lt;li data-end=&quot;1162&quot; data-start=&quot;1046&quot;&gt;It added &lt;strong&gt;Fundamental Duties&lt;/strong&gt; to the Constitution under &lt;strong&gt;Article 51A&lt;/strong&gt;, listing 10 duties for Indian citizens to follow.&lt;/li&gt;
	&lt;li data-end=&quot;1560&quot; data-start=&quot;1323&quot;&gt;The amendment gave precedence to the &lt;strong&gt;Directive Principles of State Policy (DPSP)&lt;/strong&gt; over the Fundamental Rights in case of conflict, altering the balance of constitutional principles.&lt;/li&gt;
	&lt;li data-end=&quot;1654&quot; data-start=&quot;1565&quot;&gt;It introduced provisions like curbing judicial review powers and reducing the authority of the judiciary, thus strengthening the power of the Parliament and the executive.&lt;/li&gt;
	&lt;li data-end=&quot;1999&quot; data-start=&quot;1809&quot;&gt;The 42nd Amendment also extended the tenure of the Lok Sabha and State Legislative Assemblies from &lt;strong&gt;5 years to 6 years&lt;/strong&gt;, though this was later reversed by the &lt;strong&gt;44th Amendment Act&lt;/strong&gt; in 1978.&lt;/li&gt;
	&lt;li data-end=&quot;2112&quot; data-start=&quot;2076&quot;&gt;&lt;em&gt;&lt;strong&gt;Hence, the 42nd Amendment is rightly called the &amp;quot;Mini-Constitution&amp;quot; due to its far-reaching changes.&lt;/strong&gt;&lt;/em&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;42nd Amendment Act Details:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;2410&quot; data-start=&quot;2195&quot;&gt;The amendment was introduced by the &lt;strong&gt;Indian National Congress&lt;/strong&gt; government led by &lt;strong&gt;Indira Gandhi&lt;/strong&gt;, and it is one of the most controversial amendments in India&amp;#39;s constitutional history.&lt;/li&gt;
		&lt;li data-end=&quot;2684&quot; data-start=&quot;2415&quot;&gt;It was passed during the Emergency period when civil liberties were curtailed, and the opposition was suppressed, which led to criticism of the amendment as being excessively authoritarian.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Changes to the Constitution:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;2860&quot; data-start=&quot;2735&quot;&gt;The &lt;strong&gt;Preamble&lt;/strong&gt; was amended to reflect India&amp;#39;s commitment to socialism, secularism, and national integrity.&lt;/li&gt;
		&lt;li data-end=&quot;3071&quot; data-start=&quot;2865&quot;&gt;The addition of &lt;strong&gt;Article 51A&lt;/strong&gt; introduced the Fundamental Duties, which include respecting the Constitution, promoting harmony, and safeguarding public property.&lt;/li&gt;
		&lt;li data-end=&quot;3250&quot; data-start=&quot;3076&quot;&gt;Changes to the judiciary limited its power to review amendments under Article 368, which was later nullified by the &lt;strong&gt;Minerva Mills case (1980)&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Reversal of Provisions:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;3402&quot; data-start=&quot;3301&quot;&gt;The &lt;strong&gt;44th Amendment Act (1978)&lt;/strong&gt;, passed by the Janata government, reversed some of the authoritarian provisions of the 42nd Amendment, such as the extension of the Lok Sabha&amp;#39;s term.&lt;/li&gt;
		&lt;li data-end=&quot;3580&quot; data-start=&quot;3407&quot;&gt;It restored the balance between Fundamental Rights and Directive Principles of State Policy (DPSP), ensuring that Fundamental Rights are not overridden.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Key Features of the 42nd Amendment:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;4636&quot; data-start=&quot;4411&quot;&gt;&lt;strong&gt;Article 368&lt;/strong&gt; was amended to limit judicial review of constitutional amendments.&lt;/li&gt;
		&lt;li data-end=&quot;4761&quot; data-start=&quot;4641&quot;&gt;The concept of the &lt;strong&gt;basic structure doctrine&lt;/strong&gt;, introduced by the &lt;strong&gt;Keshavananda Bharati case (1973)&lt;/strong&gt;, was challenged but later upheld by the judiciary.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Impact of the 42nd Amendment:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;5043&quot; data-start=&quot;4817&quot;&gt;It centralized power with the Parliament and the executive, which was seen as a move to undermine federalism and democracy.&lt;/li&gt;
		&lt;li data-end=&quot;5259&quot; data-start=&quot;5048&quot;&gt;It remains a significant example of how constitutional amendments can be used to alter the balance of power in a democracy.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p data-end=&quot;57&quot; data-start=&quot;0&quot;&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;42वां संशोधन&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p data-end=&quot;57&quot; data-start=&quot;0&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;284&quot; data-start=&quot;78&quot;&gt;&lt;strong&gt;42वां संशोधन अधिनियम&lt;/strong&gt;, जो &lt;strong&gt;1976&lt;/strong&gt; में अधिनियमित किया गया था, को अक्सर &lt;strong&gt;&amp;quot;मिनी-संविधान&amp;quot;&lt;/strong&gt; कहा जाता है क्योंकि इसने भारतीय संविधान में व्यापक परिवर्तन किए।&lt;/li&gt;
	&lt;li data-end=&quot;605&quot; data-start=&quot;482&quot;&gt;यह &lt;strong&gt;प्रधानमंत्री इंदिरा गांधी&lt;/strong&gt; के कार्यकाल के दौरान भारत में आपातकाल (1975-1977) की अवधि में पारित किया गया था।&lt;/li&gt;
	&lt;li data-end=&quot;692&quot; data-start=&quot;610&quot;&gt;संशोधन ने संविधान के अन्य भागों के अलावा &lt;strong&gt;प्रस्तावना&lt;/strong&gt;, &lt;strong&gt;मौलिक कर्तव्यों&lt;/strong&gt; और &lt;strong&gt;राज्य नीति के निर्देशक सिद्धांतों&lt;/strong&gt; (डीपीएसपी) में महत्वपूर्ण बदलाव किए।&lt;/li&gt;
	&lt;li data-end=&quot;1041&quot; data-start=&quot;850&quot;&gt;प्रस्तावना में &lt;strong&gt;&amp;quot;समाजवादी&amp;quot;&lt;/strong&gt;, &lt;strong&gt;&amp;quot;धर्मनिरपेक्ष&amp;quot;&lt;/strong&gt; और &lt;strong&gt;&amp;quot;अखंडता&amp;quot;&lt;/strong&gt; शब्दों को शामिल करने के लिए संशोधन किया गया था, जिससे भारतीय राज्य की धर्मनिरपेक्ष और समाजवादी प्रकृति पर जोर दिया गया।&lt;/li&gt;
	&lt;li data-end=&quot;1162&quot; data-start=&quot;1046&quot;&gt;इसने &lt;strong&gt;अनुच्छेद 51A&lt;/strong&gt; के तहत संविधान में &lt;strong&gt;मौलिक कर्तव्यों&lt;/strong&gt; को जोड़ा, जिसमें भारतीय नागरिकों के पालन के लिए 10 कर्तव्यों को सूचीबद्ध किया गया है।&lt;/li&gt;
	&lt;li data-end=&quot;1560&quot; data-start=&quot;1323&quot;&gt;संशोधन ने संघर्ष की स्थिति में मौलिक अधिकारों पर &lt;strong&gt;राज्य नीति के निर्देशक सिद्धांतों (डीपीएसपी)&lt;/strong&gt; को प्राथमिकता दी, जिससे संवैधानिक सिद्धांतों का संतुलन बदल गया।&lt;/li&gt;
	&lt;li data-end=&quot;1654&quot; data-start=&quot;1565&quot;&gt;इसने न्यायिक समीक्षा शक्तियों को कम करने और न्यायपालिका के अधिकार को कम करने जैसे प्रावधानों को पेश किया, इस प्रकार संसद और कार्यपालिका की शक्ति को मजबूत किया।&lt;/li&gt;
	&lt;li data-end=&quot;1999&quot; data-start=&quot;1809&quot;&gt;42वें संशोधन ने लोकसभा और राज्य विधान सभाओं के कार्यकाल को भी &lt;strong&gt;5 वर्ष से बढ़ाकर 6 वर्ष&lt;/strong&gt; कर दिया, हालांकि इसे बाद में 1978 में &lt;strong&gt;44वें संशोधन अधिनियम&lt;/strong&gt; द्वारा उलट दिया गया।&lt;/li&gt;
	&lt;li data-end=&quot;2112&quot; data-start=&quot;2076&quot;&gt;&lt;em&gt;&lt;strong&gt;इसलिए, 42वें संशोधन को इसके दूरगामी परिवर्तनों के कारण सही मायने में &amp;quot;मिनी-संविधान&amp;quot; कहा जाता है।&lt;/strong&gt;&lt;/em&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;42वें संशोधन अधिनियम का विवरण:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;2410&quot; data-start=&quot;2195&quot;&gt;यह संशोधन &lt;strong&gt;इंदिरा गांधी&lt;/strong&gt; के नेतृत्व वाली &lt;strong&gt;भारतीय राष्ट्रीय कांग्रेस&lt;/strong&gt; सरकार द्वारा पेश किया गया था, और यह भारत के संवैधानिक इतिहास में सबसे विवादास्पद संशोधनों में से एक है।&lt;/li&gt;
		&lt;li data-end=&quot;2684&quot; data-start=&quot;2415&quot;&gt;यह आपातकाल की अवधि के दौरान पारित किया गया था जब नागरिक स्वतंत्रताएं कम कर दी गई थीं, और विपक्ष को दबा दिया गया था, जिसके कारण संशोधन की अत्यधिक सत्तावादी होने के रूप में आलोचना हुई।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;संविधान में परिवर्तन:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;2860&quot; data-start=&quot;2735&quot;&gt;&lt;strong&gt;प्रस्तावना&lt;/strong&gt; को समाजवाद, धर्मनिरपेक्षता और राष्ट्रीय अखंडता के प्रति भारत की प्रतिबद्धता को दर्शाने के लिए संशोधित किया गया था।&lt;/li&gt;
		&lt;li data-end=&quot;3071&quot; data-start=&quot;2865&quot;&gt;&lt;strong&gt;अनुच्छेद 51A&lt;/strong&gt; के अतिरिक्त ने मौलिक कर्तव्यों को पेश किया, जिसमें संविधान का सम्मान करना, सद्भाव को बढ़ावा देना और सार्वजनिक संपत्ति की रक्षा करना शामिल है।&lt;/li&gt;
		&lt;li data-end=&quot;3250&quot; data-start=&quot;3076&quot;&gt;न्यायपालिका में बदलाव ने अनुच्छेद 368 के तहत संशोधनों की समीक्षा करने की अपनी शक्ति को सीमित कर दिया, जिसे बाद में &lt;strong&gt;मिनर्वा मिल्स मामले (1980)&lt;/strong&gt; द्वारा रद्द कर दिया गया।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;प्रावधानों का उलटना:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;3402&quot; data-start=&quot;3301&quot;&gt;&lt;strong&gt;44वां संशोधन अधिनियम (1978)&lt;/strong&gt;, जो जनता सरकार द्वारा पारित किया गया था, ने 42वें संशोधन के कुछ सत्तावादी प्रावधानों को उलट दिया, जैसे कि लोकसभा के कार्यकाल का विस्तार।&lt;/li&gt;
		&lt;li data-end=&quot;3580&quot; data-start=&quot;3407&quot;&gt;इसने मौलिक अधिकारों और राज्य नीति के निर्देशक सिद्धांतों (डीपीएसपी) के बीच संतुलन बहाल किया, यह सुनिश्चित करते हुए कि मौलिक अधिकारों को ओवरराइड नहीं किया जाता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;42वें संशोधन की मुख्य विशेषताएं:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;4636&quot; data-start=&quot;4411&quot;&gt;&lt;strong&gt;अनुच्छेद 368&lt;/strong&gt; को संवैधानिक संशोधनों की न्यायिक समीक्षा को सीमित करने के लिए संशोधित किया गया था।&lt;/li&gt;
		&lt;li data-end=&quot;4761&quot; data-start=&quot;4641&quot;&gt;&lt;strong&gt;केशवानंद भारती मामले (1973)&lt;/strong&gt; द्वारा पेश किए गए &lt;strong&gt;मूल संरचना सिद्धांत&lt;/strong&gt; की अवधारणा को चुनौती दी गई थी लेकिन बाद में न्यायपालिका द्वारा बरकरार रखा गया था।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;42वें संशोधन का प्रभाव:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;5043&quot; data-start=&quot;4817&quot;&gt;इसने संसद और कार्यपालिका के साथ शक्ति को केंद्रीकृत किया, जिसे संघवाद और लोकतंत्र को कमजोर करने के लिए एक कदम के रूप में देखा गया।&lt;/li&gt;
		&lt;li data-end=&quot;5259&quot; data-start=&quot;5048&quot;&gt;यह एक महत्वपूर्ण उदाहरण बना हुआ है कि कैसे संवैधानिक संशोधनों का उपयोग लोकतंत्र में शक्ति के संतुलन को बदलने के लिए किया जा सकता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p data-end=&quot;&quot; data-start=&quot;&quot;&gt;The correct answer is &lt;u&gt;&lt;strong&gt;It is self-sufficient across the full value chain&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;span align-items:=&quot;&quot; display:=&quot;&quot; gap:=&quot;&quot; style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;India&amp;#39;s textile sector&lt;/strong&gt; is unique because it is &lt;strong&gt;self-sufficient across the full value chain&lt;/strong&gt;, from the production of raw materials such as cotton, jute, and silk to the manufacturing of finished goods like apparel and home textiles.&lt;/li&gt;
	&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;India is one of the largest producers of &lt;strong&gt;cotton, jute, and silk&lt;/strong&gt; globally, and it has a robust infrastructure supporting spinning, weaving, dyeing, and finishing processes.&lt;/li&gt;
	&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;The sector is &lt;strong&gt;vertically integrated&lt;/strong&gt;, meaning it can handle every stage of production domestically without relying significantly on imports. This makes it resilient and competitive in global markets.&amp;nbsp;&lt;em&gt;&lt;span font-weight:=&quot;&quot; style=&quot;&quot;&gt;Hence, statement 3 is correct.&lt;/span&gt;&lt;/em&gt;&lt;/li&gt;
	&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;Unlike other countries that might focus solely on raw materials or finished products, India&amp;rsquo;s textile industry covers everything from &lt;strong&gt;fiber production&lt;/strong&gt; to &lt;strong&gt;value-added exports&lt;/strong&gt; such as designer garments and technical textiles.&lt;/li&gt;
	&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;Statements 1, 2, and 4 are incorrect because the Indian textile sector does not export only raw materials (as it exports finished goods extensively), does not rely on importing finished products (due to its self-sufficiency), and caters to both domestic and international markets rather than solely focusing on domestic consumption.&amp;nbsp;&lt;em color:=&quot;&quot; style=&quot;&quot;&gt;&lt;span font-weight:=&quot;&quot; style=&quot;&quot;&gt;Hence, statement 3&amp;nbsp;is the distinguishing feature.&lt;/span&gt;&lt;/em&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span align-items:=&quot;&quot; display:=&quot;&quot; gap:=&quot;&quot; style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Key Features of India&amp;rsquo;s Textile Sector:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;Age:&lt;/strong&gt; The textile industry in India is one of the oldest industries, dating back centuries. It has a long tradition of producing high-quality fabrics like silk and cotton.&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;Location:&lt;/strong&gt; Major textile hubs include &lt;strong&gt;Tiruppur (Tamil Nadu), Surat (Gujarat), Ludhiana (Punjab), and Mumbai (Maharashtra).&lt;/strong&gt;&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;Exports:&lt;/strong&gt; India is a major exporter of textiles and garments to countries like the &lt;strong&gt;USA, UK, UAE, and Germany&lt;/strong&gt;. It contributes significantly to global textile trade.&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;Employment:&lt;/strong&gt; The textile industry is the &lt;strong&gt;second-largest employer&lt;/strong&gt; in India, providing jobs to millions of people directly and indirectly.&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;Government Support:&lt;/strong&gt; The government has introduced initiatives such as the &lt;strong&gt;Production Linked Incentive (PLI) Scheme&lt;/strong&gt;, &lt;strong&gt;Technology Upgradation Fund Scheme (TUFS)&lt;/strong&gt;, and &lt;strong&gt;National Technical Textiles Mission&lt;/strong&gt; to boost the sector.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Characteristics of Incorrect Options:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;Option 1:&lt;/strong&gt; India does not export only raw materials. It exports a significant amount of finished products, including garments, technical textiles, and home furnishings.&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;Option 2:&lt;/strong&gt; India does not import most of its finished products. Its self-sufficient infrastructure ensures that it produces most finished goods domestically.&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;Option 4:&lt;/strong&gt; India&amp;rsquo;s textile industry caters to both &lt;strong&gt;domestic and international markets&lt;/strong&gt;. It is not limited to domestic consumption.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span align-items:=&quot;&quot; display:=&quot;&quot; gap:=&quot;&quot; style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Global Ranking:&lt;/strong&gt; India is the &lt;strong&gt;second-largest textile and garment producer&lt;/strong&gt; globally, second only to China.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Technical Textiles:&lt;/strong&gt; India is increasingly investing in &lt;strong&gt;technical textiles&lt;/strong&gt;, which are used in industries like healthcare, construction, and automotive.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Challenges:&lt;/strong&gt; Despite its strengths, the sector faces challenges such as &lt;strong&gt;high input costs, stiff competition from China, and fluctuating demand&lt;/strong&gt; in global markets.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Opportunities:&lt;/strong&gt; Initiatives like &lt;strong&gt;&amp;lsquo;Make in India&amp;rsquo;&lt;/strong&gt; and increasing demand for sustainable and eco-friendly textiles offer immense growth opportunities for the sector.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p data-end=&quot;&quot; data-start=&quot;&quot;&gt;सही उत्तर है &lt;u&gt;&lt;strong&gt;यह पूर्ण मूल्य श्रृंखला में आत्मनिर्भर है&lt;/strong&gt;&lt;/u&gt;।&lt;/p&gt;

&lt;p data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;span align-items:=&quot;&quot; display:=&quot;&quot; gap:=&quot;&quot; style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;भारत का कपड़ा क्षेत्र&lt;/strong&gt; अद्वितीय है क्योंकि यह &lt;strong&gt;कच्चे माल के उत्पादन&lt;/strong&gt; जैसे कपास, जूट और रेशम से लेकर परिधान और घरेलू वस्त्र जैसे तैयार माल के निर्माण तक &lt;strong&gt;पूर्ण मूल्य श्रृंखला में आत्मनिर्भर&lt;/strong&gt; है।&lt;/li&gt;
	&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;भारत विश्व स्तर पर &lt;strong&gt;कपास, जूट और रेशम&lt;/strong&gt; के सबसे बड़े उत्पादकों में से एक है, और इसके पास कताई, बुनाई, रंगाई और परिष्करण प्रक्रियाओं का समर्थन करने वाला एक मजबूत बुनियादी ढांचा है।&lt;/li&gt;
	&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;यह क्षेत्र &lt;strong&gt;ऊर्ध्वाधर रूप से एकीकृत&lt;/strong&gt; है, जिसका अर्थ है कि यह आयात पर महत्वपूर्ण रूप से निर्भर हुए बिना घरेलू स्तर पर उत्पादन के हर चरण को संभाल सकता है। यह इसे वैश्विक बाजारों में लचीला और प्रतिस्पर्धी बनाता है। &lt;em&gt;&lt;span font-weight:=&quot;&quot; style=&quot;&quot;&gt;इसलिए, कथन 3 सही है।&lt;/span&gt;&lt;/em&gt;&lt;/li&gt;
	&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;अन्य देशों के विपरीत जो केवल कच्चे माल या तैयार उत्पादों पर ध्यान केंद्रित कर सकते हैं, भारत का कपड़ा उद्योग &lt;strong&gt;फाइबर उत्पादन&lt;/strong&gt; से लेकर &lt;strong&gt;मूल्य वर्धित निर्यात&lt;/strong&gt; जैसे डिजाइनर वस्त्र और तकनीकी वस्त्र तक सब कुछ कवर करता है।&lt;/li&gt;
	&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;कथन 1, 2 और 4 गलत हैं क्योंकि भारतीय कपड़ा क्षेत्र केवल कच्चे माल का निर्यात नहीं करता है (क्योंकि यह बड़े पैमाने पर तैयार माल का निर्यात करता है), तैयार उत्पादों के आयात पर निर्भर नहीं करता है (अपनी आत्मनिर्भरता के कारण), और केवल घरेलू खपत पर ध्यान केंद्रित करने के बजाय घरेलू और अंतर्राष्ट्रीय दोनों बाजारों को पूरा करता है। &lt;em color:=&quot;&quot; style=&quot;&quot;&gt;&lt;span font-weight:=&quot;&quot; style=&quot;&quot;&gt;इसलिए, कथन 3 विशिष्ट विशेषता है।&lt;/span&gt;&lt;/em&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span align-items:=&quot;&quot; display:=&quot;&quot; gap:=&quot;&quot; style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;भारत के कपड़ा क्षेत्र की मुख्य विशेषताएं:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;आयु:&lt;/strong&gt; भारत में कपड़ा उद्योग सबसे पुराने उद्योगों में से एक है, जो सदियों पहले का है। रेशम और कपास जैसे उच्च गुणवत्ता वाले कपड़े बनाने की इसकी एक लंबी परंपरा है।&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;स्थान:&lt;/strong&gt; प्रमुख कपड़ा केंद्र &lt;strong&gt;तिरुपुर (तमिलनाडु), सूरत (गुजरात), लुधियाना (पंजाब), और मुंबई (महाराष्ट्र)&lt;/strong&gt; हैं।&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;निर्यात:&lt;/strong&gt; भारत &lt;strong&gt;संयुक्त राज्य अमेरिका, यूके, यूएई और जर्मनी&lt;/strong&gt; जैसे देशों को वस्त्रों और परिधानों का एक प्रमुख निर्यातक है। यह वैश्विक कपड़ा व्यापार में महत्वपूर्ण योगदान देता है।&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;रोजगार:&lt;/strong&gt; कपड़ा उद्योग भारत में &lt;strong&gt;दूसरा सबसे बड़ा नियोक्ता&lt;/strong&gt; है, जो लाखों लोगों को प्रत्यक्ष और अप्रत्यक्ष रूप से रोजगार प्रदान करता है।&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;सरकारी सहायता:&lt;/strong&gt; सरकार ने इस क्षेत्र को बढ़ावा देने के लिए &lt;strong&gt;उत्पादन लिंक्ड प्रोत्साहन (&lt;/strong&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;PLI&lt;/span&gt;&lt;strong&gt;) योजना&lt;/strong&gt;, &lt;strong&gt;प्रौद्योगिकी उन्नयन निधि योजना (&lt;/strong&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;TUFS&lt;/span&gt;&lt;strong&gt;)&lt;/strong&gt; और &lt;strong&gt;राष्ट्रीय तकनीकी वस्त्र मिशन&lt;/strong&gt; जैसी पहल शुरू की हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;गलत विकल्पों की विशेषताएं:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;विकल्प 1:&lt;/strong&gt; भारत केवल कच्चे माल का निर्यात नहीं करता है। यह परिधान, तकनीकी वस्त्र और घरेलू साज-सामान सहित तैयार उत्पादों की एक महत्वपूर्ण मात्रा का निर्यात करता है।&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;विकल्प 2:&lt;/strong&gt; भारत अपने अधिकांश तैयार उत्पादों का आयात नहीं करता है। इसका आत्मनिर्भर बुनियादी ढांचा यह सुनिश्चित करता है कि यह अधिकांश तैयार माल का उत्पादन घरेलू स्तर पर करता है।&lt;/li&gt;
		&lt;li data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;strong&gt;विकल्प 4:&lt;/strong&gt; भारत का कपड़ा उद्योग &lt;strong&gt;घरेलू और अंतर्राष्ट्रीय दोनों बाजारों&lt;/strong&gt; को पूरा करता है। यह घरेलू खपत तक सीमित नहीं है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span align-items:=&quot;&quot; display:=&quot;&quot; gap:=&quot;&quot; style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;वैश्विक रैंकिंग:&lt;/strong&gt; भारत विश्व स्तर पर &lt;strong&gt;दूसरा सबसे बड़ा कपड़ा और परिधान उत्पादक&lt;/strong&gt; है, जो चीन के बाद दूसरे स्थान पर है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;तकनीकी वस्त्र:&lt;/strong&gt; भारत तेजी से &lt;strong&gt;तकनीकी वस्त्रों&lt;/strong&gt; में निवेश कर रहा है, जिनका उपयोग स्वास्थ्य सेवा, निर्माण और ऑटोमोटिव जैसे उद्योगों में किया जाता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;चुनौतियां:&lt;/strong&gt; अपनी ताकत के बावजूद, इस क्षेत्र को &lt;strong&gt;उच्च इनपुट लागत, चीन से कड़ी प्रतिस्पर्धा और वैश्विक बाजारों में अस्थिर मांग&lt;/strong&gt; जैसी चुनौतियों का सामना करना पड़ता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;अवसर:&lt;/strong&gt; &lt;strong&gt;&amp;lsquo;मेक इन इंडिया&amp;rsquo;&lt;/strong&gt; जैसी पहल और टिकाऊ और पर्यावरण के अनुकूल वस्त्रों की बढ़ती मांग इस क्षेत्र के लिए अपार विकास के अवसर प्रदान करती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Saguna and Nirguna&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;u style=&quot;font-size: 21px; font-weight: bolder; font-family: var(--bs-body-font-family); text-align: var(--bs-body-text-align);&quot;&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The Bhakti movement in India emphasized devotion to a personal deity and was categorized into two main traditions: &lt;strong&gt;Saguna&lt;/strong&gt; and &lt;strong&gt;Nirguna&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Saguna Bhakti&lt;/strong&gt; refers to devotion to a deity with form and attributes, such as Lord Krishna, Rama, or Goddess Durga.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Nirguna Bhakti&lt;/strong&gt; focuses on the worship of a formless, infinite, and abstract divine reality, often associated with concepts like the ultimate truth or Brahman.&lt;/li&gt;
	&lt;li&gt;Famous saints like &lt;strong&gt;Meera Bai, Tulsidas, and Surdas&lt;/strong&gt; were proponents of Saguna Bhakti, while &lt;strong&gt;Kabir and Guru Nanak&lt;/strong&gt; emphasized Nirguna Bhakti.&lt;/li&gt;
	&lt;li&gt;The two traditions reflect different approaches to spirituality, offering flexibility for individual beliefs and practices within the Bhakti movement.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Vedic and Non-Vedic&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;The terms &amp;quot;Vedic&amp;quot; and &amp;quot;Non-Vedic&amp;quot; classify traditions based on their alignment with the Vedas.&lt;/li&gt;
		&lt;li&gt;Vedic traditions include rituals, sacrifices, and practices outlined in the Vedas, while Non-Vedic traditions involve independent or alternative spiritual practices, such as Jainism and Buddhism.&lt;/li&gt;
		&lt;li&gt;However, the Bhakti movement does not strictly align with this classification as it incorporates elements from both.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Orthodox and Reformist&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;The &amp;quot;Orthodox&amp;quot; approach adheres strictly to traditional practices and scriptures, while the &amp;quot;Reformist&amp;quot; approach focuses on modifying or reforming traditional religious practices.&lt;/li&gt;
		&lt;li&gt;While the Bhakti movement did involve some reformist ideas, it is not categorized within this binary classification.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Shaiva and Vaishnava&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;Shaiva and Vaishnava traditions refer to sects within Hinduism that worship Lord Shiva and Lord Vishnu, respectively, as the supreme deity.&lt;/li&gt;
		&lt;li&gt;These sects are part of the broader Bhakti traditions but are not the two main categories of Bhakti worship.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;सगुण और निर्गुण&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;u style=&quot;font-size: 21px; font-weight: bolder; font-family: var(--bs-body-font-family); text-align: var(--bs-body-text-align);&quot;&gt;मुख्य बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;भारत में भक्ति आंदोलन ने एक व्यक्तिगत देवता के प्रति भक्ति पर जोर दिया और इसे दो मुख्य परंपराओं में वर्गीकृत किया गया: &lt;strong&gt;सगुण&lt;/strong&gt; और &lt;strong&gt;निर्गुण&lt;/strong&gt;।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;सगुण भक्ति&lt;/strong&gt; का तात्पर्य रूप और गुणों वाले देवता के प्रति भक्ति से है, जैसे कि भगवान कृष्ण, राम या देवी दुर्गा।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;निर्गुण भक्ति&lt;/strong&gt; एक निराकार, अनंत और अमूर्त दिव्य वास्तविकता की पूजा पर केंद्रित है, जो अक्सर परम सत्य या ब्रह्म जैसी अवधारणाओं से जुड़ी होती है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;मीरा बाई, तुलसीदास और सूरदास&lt;/strong&gt; जैसे प्रसिद्ध संत सगुण भक्ति के समर्थक थे, जबकि &lt;strong&gt;कबीर और गुरु नानक&lt;/strong&gt; ने निर्गुण भक्ति पर जोर दिया।&lt;/li&gt;
	&lt;li&gt;ये दोनों परंपराएं आध्यात्मिकता के विभिन्न दृष्टिकोणों को दर्शाती हैं, जो भक्ति आंदोलन के भीतर व्यक्तिगत मान्यताओं और प्रथाओं के लिए लचीलापन प्रदान करती हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;अतिरिक्त जानकारी&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;वैदिक और गैर-वैदिक&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&amp;quot;वैदिक&amp;quot; और &amp;quot;गैर-वैदिक&amp;quot; शब्द वेदों के साथ उनके संरेखण के आधार पर परंपराओं को वर्गीकृत करते हैं।&lt;/li&gt;
		&lt;li&gt;वैदिक परंपराओं में वेदों में उल्लिखित अनुष्ठान, बलिदान और प्रथाएं शामिल हैं, जबकि गैर-वैदिक परंपराओं में स्वतंत्र या वैकल्पिक आध्यात्मिक प्रथाएं शामिल हैं, जैसे कि जैन धर्म और बौद्ध धर्म।&lt;/li&gt;
		&lt;li&gt;हालांकि, भक्ति आंदोलन इस वर्गीकरण के साथ सख्ती से संरेखित नहीं है क्योंकि इसमें दोनों के तत्व शामिल हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;रूढ़िवादी और सुधारवादी&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;&amp;quot;रूढ़िवादी&amp;quot; दृष्टिकोण पारंपरिक प्रथाओं और शास्त्रों का सख्ती से पालन करता है, जबकि &amp;quot;सुधारवादी&amp;quot; दृष्टिकोण पारंपरिक धार्मिक प्रथाओं को संशोधित या सुधारने पर केंद्रित है।&lt;/li&gt;
		&lt;li&gt;जबकि भक्ति आंदोलन में कुछ सुधारवादी विचार शामिल थे, इसे इस द्विआधारी वर्गीकरण के भीतर वर्गीकृत नहीं किया गया है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;शैव और वैष्णव&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;शैव और वैष्णव परंपराएं हिंदू धर्म के भीतर उन संप्रदायों को संदर्भित करती हैं जो क्रमशः भगवान शिव और भगवान विष्णु को सर्वोच्च देवता के रूप में पूजते हैं।&lt;/li&gt;
		&lt;li&gt;ये संप्रदाय व्यापक भक्ति परंपराओं का हिस्सा हैं लेकिन भक्ति पूजा की दो मुख्य श्रेणियां नहीं हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;
